  const loadEmployeeSchedule = async (employeeId: string) => {
    try {
      const key = scheduleKeyForEmployee(employeeId);
      const { data } = await supabase.from('app_settings').select('value').eq('key', key).maybeSingle();
      const parsed = data?.value ? (typeof data.value === 'string' ? JSON.parse(data.value) : data.value) : [];
      let dates: string[] = [];
      let offDates: string[] = [];
      let locked = false;
      if (Array.isArray(parsed)) {
        dates = parsed.map((x: any) => String(x)).filter(Boolean);
      } else if (parsed && typeof parsed === 'object') {
        dates = Array.isArray((parsed as any).dates) ? (parsed as any).dates.map((x: any) => String(x)).filter(Boolean) : [];
        offDates = Array.isArray((parsed as any).offDates) ? (parsed as any).offDates.map((x: any) => String(x)).filter(Boolean) : [];
        locked = Boolean((parsed as any).locked);
      }
      setCwScheduleDates(dates);
      setCwScheduleOffDates(offDates);
      setCwScheduleDraftDates(dates);
      setCwScheduleDraftOffDates(offDates);
      setCwScheduleLocked(locked);
    } catch {
      setCwScheduleDates([]);
      setCwScheduleOffDates([]);
      setCwScheduleDraftDates([]);
      setCwScheduleDraftOffDates([]);
      setCwScheduleLocked(false);
    }
  };

