  const [fboPalletHint, setFboPalletHint] = useState<FboPalletHint | null>(null);
  const [supplyStats, setSupplyStats] = useState({ boxes: 0, items: 0 });
  const fboPalletBrands = useMemo(() => Array.from(new Set(fboPalletProducts.map((p) => p.brand).filter(Boolean))).sort(), [fboPalletProducts]);
  const fboPalletCategories = useMemo(() => Array.from(new Set(fboPalletProducts.map((p) => p.category).filter(Boolean))).sort(), [fboPalletProducts]);
  const filteredFboPalletProducts = useMemo(() => {
    const q = fboPalletProductSearch.trim().toLowerCase();
    return fboPalletProducts.filter((p) => {
      if (fboPalletBrandFilter && p.brand !== fboPalletBrandFilter) return false;
      if (fboPalletCategoryFilter && p.category !== fboPalletCategoryFilter) return false;
      if (!q) return true;
      return [p.title, p.vendor_code, p.nm_id, p.barcode, p.size, p.color].some((value) => String(value || '').toLowerCase().includes(q));
    });
  }, [fboPalletBrandFilter, fboPalletCategoryFilter, fboPalletProductSearch, fboPalletProducts]);
  const [apiBoxCount, setApiBoxCount] = useState('1');
  const [loadingApiBoxes, setLoadingApiBoxes] = useState(false);
  const [fboBoxesExcelFile, setFboBoxesExcelFile] = useState<File | null>(null);
  const [fboBoxesGenerating, setFboBoxesGenerating] = useState(false);
  const [fboBoxesSupplierId, setFboBoxesSupplierId] = useState<string>('');
  const [fboBoxesTotalLabels, setFboBoxesTotalLabels] = useState<number>(0);
  const [fboBoxesRangeFrom, setFboBoxesRangeFrom] = useState<string>('1');
  const [fboBoxesRangeTo, setFboBoxesRangeTo] = useState<string>('');
  const [supplySyncExcelFile, setSupplySyncExcelFile] = useState<File | null>(null);
  const [supplySyncOpen, setSupplySyncOpen] = useState(false);
  const [supplySyncLoading, setSupplySyncLoading] = useState(false);
  const [fboOfflineMode, setFboOfflineMode] = useState(false);
  const [showNameSequencePrintModal, setShowNameSequencePrintModal] = useState(false);
  const [nameSequencePrintForm, setNameSequencePrintForm] = useState({ name: '', quantity: '1' });
  const [nameSequencePrintLoading, setNameSequencePrintLoading] = useState(false);
  const [offlineFboSession, setOfflineFboSession] = useState<OfflineFboSession | null>(null);
  const [offlineFboValidation, setOfflineFboValidation] = useState<OfflineFboValidationSummary | null>(null);
  const [offlineFboValidationLoading, setOfflineFboValidationLoading] = useState(false);
  const [offlineFboUploadLoading, setOfflineFboUploadLoading] = useState(false);
  const [showOfflineFboHistory, setShowOfflineFboHistory] = useState(false);
  const [offlineFboHistorySessions, setOfflineFboHistorySessions] = useState<OfflineFboSession[]>([]);
  const [offlineFboHistoryLoading, setOfflineFboHistoryLoading] = useState(false);
  const [offlineFboUnsyncedStats, setOfflineFboUnsyncedStats] = useState({ sessions: 0, items: 0 });
  const offlineFboSessionRef = useRef<OfflineFboSession | null>(null);


  const getOfflineFboStorageKey = (supplyId: string) => `fbo_offline_session_v1_${supplyId}`;
  const OFFLINE_FBO_DB_NAME = 'skladpro_offline_fbo_v1';
  const OFFLINE_FBO_DB_STORE = 'sessions';

  const buildEmptyOfflineFboSession = (supply: Supply): OfflineFboSession => ({
    supply_id: supply.id,
    supplier_id: supply.supplier_id,
    supply_name: supply.name,
    boxes: [],
    items: [],
    updated_at: new Date().toISOString(),
    base_box_number: 0,
  });

  const normalizeOfflineFboSession = (supply: Supply, parsed: any): OfflineFboSession => ({
    ...buildEmptyOfflineFboSession(supply),
    ...parsed,
    supply_id: supply.id,
    supplier_id: supply.supplier_id,
    supply_name: supply.name,
    boxes: Array.isArray(parsed?.boxes) ? parsed.boxes : [],
    items: Array.isArray(parsed?.items) ? parsed.items : [],
    updated_at: String(parsed?.updated_at || new Date().toISOString()),
    base_box_number: Number.isFinite(Number(parsed?.base_box_number)) ? Math.max(0, Number(parsed?.base_box_number)) : 0,
  });

  const getMaxNumericBoxName = (rows: Array<{ name?: string | null }> = []) => rows.reduce((max, row) => {
    const value = parseInt(String(row?.name || '').trim(), 10);
    return Number.isFinite(value) && value > max ? value : max;
  }, 0);

  const openOfflineFboDb = (): Promise<IDBDatabase> => new Promise((resolve, reject) => {
    if (typeof indexedDB === 'undefined') {
      reject(new Error('IndexedDB недоступен'));
      return;
    }
    const request = indexedDB.open(OFFLINE_FBO_DB_NAME, 1);
    request.onupgradeneeded = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains(OFFLINE_FBO_DB_STORE)) {
        db.createObjectStore(OFFLINE_FBO_DB_STORE, { keyPath: 'supply_id' });
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error || new Error('Не удалось открыть IndexedDB'));
  });

  const readLegacyOfflineFboSession = (supply: Supply): OfflineFboSession | null => {
    try {
      const raw = localStorage.getItem(getOfflineFboStorageKey(supply.id));
      if (!raw) return null;
      return normalizeOfflineFboSession(supply, JSON.parse(raw || '{}'));
    } catch {
      return null;
    }
  };

  const readOfflineFboSessionFromDevice = async (supply: Supply): Promise<OfflineFboSession> => {
    const fallback = buildEmptyOfflineFboSession(supply);
    try {
      const db = await openOfflineFboDb();
      const stored = await new Promise<any>((resolve, reject) => {
        const tx = db.transaction(OFFLINE_FBO_DB_STORE, 'readonly');
        const store = tx.objectStore(OFFLINE_FBO_DB_STORE);
        const request = store.get(supply.id);
        request.onsuccess = () => resolve(request.result || null);
        request.onerror = () => reject(request.error || new Error('Не удалось прочитать оффлайн-сессию'));
      });
      db.close();
      if (stored) {
        return normalizeOfflineFboSession(supply, stored);
      }
    } catch (e) {
      console.error('readOfflineFboSessionFromDevice error', e);
    }

    const legacy = readLegacyOfflineFboSession(supply);
    if (legacy) {
      await writeOfflineFboSessionToDevice(legacy);
      localStorage.removeItem(getOfflineFboStorageKey(supply.id));
      return legacy;
    }
    return fallback;
  };

  const scheduleOfflineFboStatsRefresh = () => {
    if (offlineFboStatsRefreshTimeoutRef.current) {
      window.clearTimeout(offlineFboStatsRefreshTimeoutRef.current);
    }
    offlineFboStatsRefreshTimeoutRef.current = window.setTimeout(() => {
      refreshOfflineFboDeviceStats().catch(() => undefined);
    }, 400);
  };

  const writeOfflineFboSessionToDevice = async (session: OfflineFboSession) => {
    try {
      const db = await openOfflineFboDb();
      await new Promise<void>((resolve, reject) => {
        const tx = db.transaction(OFFLINE_FBO_DB_STORE, 'readwrite');
        const store = tx.objectStore(OFFLINE_FBO_DB_STORE);
        const request = store.put({
          ...session,
          updated_at: new Date().toISOString(),
        });
        request.onsuccess = () => resolve();
        request.onerror = () => reject(request.error || new Error('Не удалось сохранить оффлайн-сессию'));
      });
      db.close();
      localStorage.removeItem(getOfflineFboStorageKey(session.supply_id));
      scheduleOfflineFboStatsRefresh();
    } catch (e) {
      console.error('writeOfflineFboSessionToDevice error', e);
    }
  };

  const clearOfflineFboSessionFromDevice = async (supplyId: string) => {
    localStorage.removeItem(getOfflineFboStorageKey(supplyId));
    try {
      const db = await openOfflineFboDb();
      await new Promise<void>((resolve, reject) => {
        const tx = db.transaction(OFFLINE_FBO_DB_STORE, 'readwrite');
        const store = tx.objectStore(OFFLINE_FBO_DB_STORE);
        const request = store.delete(supplyId);
        request.onsuccess = () => resolve();
        request.onerror = () => reject(request.error || new Error('Не удалось удалить оффлайн-сессию'));
      });
      db.close();
      scheduleOfflineFboStatsRefresh();
    } catch (e) {
      console.error('clearOfflineFboSessionFromDevice error', e);
    }
  };

  const listOfflineFboSessionsFromDevice = async (): Promise<OfflineFboSession[]> => {
    try {
      const db = await openOfflineFboDb();
      const rows = await new Promise<any[]>((resolve, reject) => {
        const tx = db.transaction(OFFLINE_FBO_DB_STORE, 'readonly');
        const store = tx.objectStore(OFFLINE_FBO_DB_STORE);
        const request = store.getAll();
        request.onsuccess = () => resolve(Array.isArray(request.result) ? request.result : []);
        request.onerror = () => reject(request.error || new Error('Не удалось прочитать список оффлайн-сессий'));
      });
      db.close();
      return (rows || [])
        .filter((row) => row?.supply_id)
        .sort((a, b) => String(b?.updated_at || '').localeCompare(String(a?.updated_at || '')));
    } catch (e) {
      console.error('listOfflineFboSessionsFromDevice error', e);
      return [];
    }
  };

  const refreshOfflineFboDeviceStats = async () => {
    const sessions = await listOfflineFboSessionsFromDevice();
    const normalized = sessions.filter((session) => (session?.boxes?.length || 0) || (session?.items?.length || 0));
    setOfflineFboUnsyncedStats({
      sessions: normalized.length,
      items: normalized.reduce((acc, session) => acc + Number(session?.items?.length || 0), 0),
    });
    return normalized;
  };

  const loadOfflineFboHistory = async () => {
    setOfflineFboHistoryLoading(true);
    try {
      const sessions = await refreshOfflineFboDeviceStats();
      setOfflineFboHistorySessions(sessions);
    } finally {
      setOfflineFboHistoryLoading(false);
    }
  };

  const handleOpenOfflineHistorySession = async (session: OfflineFboSession) => {
    const targetSupply = suppliesList.find((s) => s.id === session.supply_id);
    if (!targetSupply) {
      showToast('Поставка для этой оффлайн-сессии не найдена в списке', 'error');
      return;
    }
    setCurrentSupply(targetSupply);
    setCurrentBox(session.boxes?.[0] || null);
    setSupplyStep('SUPPLY');
    setFboOfflineMode(true);
    offlineFboSessionRef.current = session;
    setOfflineFboSession(session);
    applyOfflineFboSessionToUi(session, session.boxes?.[0]?.id || null);
    setShowOfflineFboHistory(false);
  };

  const handleDeleteOfflineHistorySession = async (session: OfflineFboSession) => {
    if (!window.confirm(`Удалить оффлайн-сессию ${session.supply_name || session.supply_id}?`)) return;
    await clearOfflineFboSessionFromDevice(session.supply_id);
    if (currentSupply?.id === session.supply_id) {
      offlineFboSessionRef.current = null;
      setOfflineFboSession(null);
      setOfflineFboValidation(null);
      if (fboOfflineMode) {
        applyOfflineFboSessionToUi(buildEmptyOfflineFboSession(currentSupply), null);
      }
    }
    await loadOfflineFboHistory();
    showToast('Оффлайн-сессия удалена с устройства', 'success');
  };

  const applyOfflineFboSessionToUi = useCallback((session: OfflineFboSession, activeBoxId?: string | null) => {
    setBoxesList(session.boxes || []);
    setSupplyStats({ boxes: (session.boxes || []).length, items: (session.items || []).length });
    const boxId = activeBoxId || '';
    setBoxItems(boxId ? (session.items || []).filter((item) => item.box_id === boxId) : []);
  }, []);

  const updateOfflineFboSession = (mutate: (session: OfflineFboSession) => OfflineFboSession, activeBoxId?: string | null) => {
    if (!currentSupply) return null;
    const base = offlineFboSessionRef.current && offlineFboSessionRef.current.supply_id === currentSupply.id
      ? offlineFboSessionRef.current
      : buildEmptyOfflineFboSession(currentSupply);
    const next = mutate({
      ...base,
      boxes: [...(base.boxes || [])],
      items: [...(base.items || [])],
      updated_at: new Date().toISOString(),
    });
    offlineFboSessionRef.current = next;
    if (offlineFboSessionWriteTimeoutRef.current) {
      window.clearTimeout(offlineFboSessionWriteTimeoutRef.current);
    }
    offlineFboSessionWriteTimeoutRef.current = window.setTimeout(() => {
      writeOfflineFboSessionToDevice(next).catch(() => undefined);
    }, 120);
    setOfflineFboSession(next);
    applyOfflineFboSessionToUi(next, activeBoxId);
    return next;
  };

  const validateOfflineFboSession = async () => {
    if (!currentSupply) return null;

    const session = offlineFboSession && offlineFboSession.supply_id === currentSupply.id
      ? offlineFboSession
      : await readOfflineFboSessionFromDevice(currentSupply);

    if (!session || !(session.boxes || []).length) {
      const summary: OfflineFboValidationSummary = {
        checkedAt: new Date().toISOString(),
        boxesCount: 0,
        itemsCount: 0,
        duplicateLocal: [],
        duplicateDb: [],
        missingProducts: [],
        ok: false,
        message: 'Нет оффлайн-коробок для проверки',
      };
      setOfflineFboValidation(summary);
      showToast(summary.message, 'error');
      return summary;
    }

    if (!(session.items || []).length) {
      const summary: OfflineFboValidationSummary = {
        checkedAt: new Date().toISOString(),
        boxesCount: session.boxes.length,
        itemsCount: 0,
        duplicateLocal: [],
        duplicateDb: [],
        missingProducts: [],
        ok: false,
        message: 'В оффлайн-сессии нет отсканированных товаров',
      };
      setOfflineFboValidation(summary);
      showToast(summary.message, 'error');
      return summary;
    }

    setOfflineFboValidationLoading(true);
    try {
      const boxNameById = new Map((session.boxes || []).map((box) => [String(box.id), String(box.name || 'Без коробки')]));
      const items = (session.items || []).filter((item) => String(item?.honest_sign_code || '').trim());
      const groupedByCode = new Map<string, SupplyItem[]>();
      items.forEach((item) => {
        const code = String(item.honest_sign_code || '').trim();
        if (!groupedByCode.has(code)) groupedByCode.set(code, []);
        groupedByCode.get(code)!.push(item);
      });

      const duplicateLocal = Array.from(groupedByCode.entries())
        .filter(([, rows]) => rows.length > 1)
        .map(([code, rows]) => ({
          code,
          boxNames: Array.from(new Set(rows.map((row) => boxNameById.get(String(row.box_id)) || 'Без коробки'))),
        }));

      delete supplierProductsIndexRef.current[currentSupply.supplier_id];
      const supplierProductsIndex = await ensureSupplierProductsIndex(currentSupply.supplier_id);
      const supplierProducts = Array.from(supplierProductsIndex.values());
      const productIdSet = new Set(supplierProducts.map((row: any) => String(row?.id || '')).filter(Boolean));
      const productBarcodeSet = new Set(supplierProducts.map((row: any) => String(row?.barcode || '').trim()).filter(Boolean));
      const productWbSkuSet = new Set(supplierProducts.map((row: any) => String(row?.wb_sku || '').trim()).filter(Boolean));
      const missingProducts = (session.items || []).filter((item) => {
        const productId = String(item?.product_id || '').trim();
        const barcode = String(item?.product?.barcode || '').trim();
        const wbSku = String(item?.product?.wb_sku || '').trim();
        const hasPayloadForAutoCreate = Boolean(barcode && String(item?.product?.name || '').trim());
        return !productIdSet.has(productId)
          && (!barcode || !productBarcodeSet.has(barcode))
          && (!wbSku || !productWbSkuSet.has(wbSku))
          && !hasPayloadForAutoCreate;
      }).map((item) => ({
        label: String(item?.product?.name || item?.product_id || 'Неизвестный товар'),
        boxName: boxNameById.get(String(item.box_id)) || 'Без коробки',
      }));

      const codes = Array.from(new Set(items.map((item) => String(item.honest_sign_code || '').trim()).filter(Boolean)));
      let duplicateDb: Array<{ code: string; boxName: string; supplyName: string }> = [];
      if (codes.length) {
        const { data: dbItems, error: dbError } = await supabase
          .from('supply_items')
          .select('honest_sign_code, box:boxes(name, deleted_at, supply:supplies(name))')
          .in('honest_sign_code', codes)
          .is('deleted_at', null)
          .limit(10000);
        if (dbError) throw dbError;

        duplicateDb = (dbItems || []).map((row: any) => ({
          code: String(row?.honest_sign_code || ''),
          boxName: String(row?.box?.name || 'Неизвестная коробка'),
          supplyName: String(row?.box?.supply?.name || 'Неизвестная поставка'),
        })).filter((row) => row.code);
      }

      const ok = !duplicateLocal.length && !duplicateDb.length && !missingProducts.length;
      const summary: OfflineFboValidationSummary = {
        checkedAt: new Date().toISOString(),
        boxesCount: session.boxes.length,
        itemsCount: session.items.length,
        duplicateLocal,
        duplicateDb,
        missingProducts,
        ok,
        message: ok
          ? 'Проверка пройдена, конфликтов не найдено'
          : `Найдены проблемы: локальные дубли ${duplicateLocal.length}, конфликты с БД ${duplicateDb.length}, отсутствующие товары ${missingProducts.length}`,
      };
      setOfflineFboValidation(summary);
      showToast(summary.message, ok ? 'success' : 'error');
      return summary;
    } catch (e: any) {
      console.error('validateOfflineFboSession error', e);
      const summary: OfflineFboValidationSummary = {
        checkedAt: new Date().toISOString(),
        boxesCount: session.boxes.length,
        itemsCount: session.items.length,
        duplicateLocal: [],
        duplicateDb: [],
        missingProducts: [],
        ok: false,
        message: 'Ошибка проверки оффлайн-сессии: ' + (e?.message || 'неизвестно'),
      };
      setOfflineFboValidation(summary);
      showToast(summary.message, 'error');
      return summary;
    } finally {
      setOfflineFboValidationLoading(false);
    }
  };

  const uploadOfflineFboSessionToDb = async () => {
    if (!currentSupply) return;

    const session = offlineFboSession && offlineFboSession.supply_id === currentSupply.id
      ? offlineFboSession
      : await readOfflineFboSessionFromDevice(currentSupply);

    if (!session || !(session.items || []).length) {
      showToast('Нет оффлайн-данных для загрузки', 'error');
      return;
    }

    const summary = await validateOfflineFboSession();
    if (!summary?.ok) {
      showToast('Сначала исправьте ошибки проверки', 'error');
      return;
    }

    setOfflineFboUploadLoading(true);
    try {
      const { data: existingBoxes, error: existingBoxesError } = await supabase
        .from('boxes')
        .select('id, name')
        .eq('supply_id', currentSupply.id)
        .is('deleted_at', null);
      if (existingBoxesError) throw existingBoxesError;

      const usedBoxNames = new Set((existingBoxes || []).map((box: any) => String(box?.name || '').trim()).filter(Boolean));
      let nextBoxNumber = Math.max(
        getMaxNumericBoxName((existingBoxes || []) as Array<{ name?: string | null }>),
        Number(session.base_box_number || 0)
      ) + 1;

      const orderedOfflineBoxes = [...(session.boxes || [])].sort((a, b) => {
        const aNum = parseInt(String(a?.name || '').trim(), 10);
        const bNum = parseInt(String(b?.name || '').trim(), 10);
        const aIsNum = Number.isFinite(aNum) && aNum > 0;
        const bIsNum = Number.isFinite(bNum) && bNum > 0;
        if (aIsNum && bIsNum) return aNum - bNum;
        return String(a?.created_at || '').localeCompare(String(b?.created_at || ''));
      });

      const offlineBoxMappings = orderedOfflineBoxes.map((box) => {
        const rawName = String(box?.name || '').trim();
        const parsed = parseInt(rawName, 10);
        const isNumeric = Number.isFinite(parsed) && parsed > 0 && String(parsed) === rawName;
        let finalName = rawName || String(nextBoxNumber++);

        if (!finalName || isNumeric || usedBoxNames.has(finalName)) {
          while (usedBoxNames.has(String(nextBoxNumber))) nextBoxNumber += 1;
          finalName = String(nextBoxNumber);
          nextBoxNumber += 1;
        }

        usedBoxNames.add(finalName);
        return {
          offlineBoxId: String(box.id),
          name: finalName,
        };
      });

      const boxInsertPayload = offlineBoxMappings.map((box) => ({ name: box.name, supply_id: currentSupply.id }));
      const insertedBoxesByName = new Map<string, string>();
      if (boxInsertPayload.length) {
        const { data: insertedBoxes, error: insertBoxesError } = await supabase
          .from('boxes')
          .insert(boxInsertPayload)
          .select('id, name');
        if (insertBoxesError) throw insertBoxesError;
        (insertedBoxes || []).forEach((box: any) => {
          insertedBoxesByName.set(String(box.name), String(box.id));
        });
      }

      const offlineBoxIdToDbBoxId = new Map<string, string>();
      offlineBoxMappings.forEach((box) => {
        const dbBoxId = insertedBoxesByName.get(box.name);
        if (dbBoxId) offlineBoxIdToDbBoxId.set(box.offlineBoxId, dbBoxId);
      });

      const productBarcodeMap = new Map<string, string>();
      const offlineBarcodes = Array.from(new Set((session.items || [])
        .map((item) => String(item?.product?.barcode || '').trim())
        .filter(Boolean)));

      for (let i = 0; i < offlineBarcodes.length; i += 500) {
        const chunk = offlineBarcodes.slice(i, i + 500);
        const { data: existingProducts, error: existingProductsError } = await supabase
          .from('products')
          .select('id, barcode')
          .eq('supplier_id', currentSupply.supplier_id)
          .in('barcode', chunk)
          .is('deleted_at', null);
        if (existingProductsError) throw existingProductsError;
        (existingProducts || []).forEach((row: any) => {
          if (row?.barcode && row?.id) productBarcodeMap.set(String(row.barcode), String(row.id));
        });
      }

      const missingProductsToInsert = new Map<string, Product>();
      (session.items || []).forEach((item) => {
        const barcode = String(item?.product?.barcode || '').trim();
        if (!barcode || productBarcodeMap.has(barcode)) return;
        if (item?.product) missingProductsToInsert.set(barcode, item.product as Product);
      });

      const missingProductsPayload = Array.from(missingProductsToInsert.values()).map((product) => ({
        supplier_id: currentSupply.supplier_id,
        name: String(product?.name || 'Товар'),
        wb_sku: String(product?.wb_sku || ''),
        barcode: String(product?.barcode || '').trim(),
        size: String(product?.size || ''),
        color: String(product?.color || ''),
      })).filter((row) => row.barcode);

      for (let i = 0; i < missingProductsPayload.length; i += 200) {
        const chunk = missingProductsPayload.slice(i, i + 200);
        if (!chunk.length) continue;
        const { data: insertedProducts, error: insertedProductsError } = await supabase
          .from('products')
          .insert(chunk)
          .select('id, barcode');
        if (insertedProductsError) throw insertedProductsError;
        (insertedProducts || []).forEach((row: any) => {
          if (row?.barcode && row?.id) productBarcodeMap.set(String(row.barcode), String(row.id));
        });
      }

      const payload = (session.items || []).map((item) => {
        const dbBoxId = offlineBoxIdToDbBoxId.get(String(item.box_id));
        const barcode = String(item?.product?.barcode || '').trim();
        const rawProductId = String(item?.product_id || '').trim();
        const resolvedProductId = (barcode && productBarcodeMap.get(barcode)) || (!rawProductId.startsWith('offline-product-') ? rawProductId : '');
        return dbBoxId && resolvedProductId ? {
          box_id: dbBoxId,
          product_id: resolvedProductId,
          honest_sign_code: item.honest_sign_code,
        } : null;
      }).filter(Boolean) as Array<{ box_id: string; product_id: string; honest_sign_code: string }>;

      for (let i = 0; i < payload.length; i += 500) {
        const chunk = payload.slice(i, i + 500);
        if (!chunk.length) continue;
        const { error } = await supabase.from('supply_items').insert(chunk);
        if (error) throw error;
      }

      await clearOfflineFboSessionFromDevice(currentSupply.id);
      setOfflineFboSession(null);
      setOfflineFboValidation(null);
      setCurrentBox(null);
      setScannedItem(null);
      setSupplyStep('SUPPLY');
      setFboOfflineMode(false);
      await fetchBoxesList(currentSupply.id);
      await fetchSupplyStats(currentSupply.id);
      showToast(`Оффлайн-сессия загружена в БД: ${payload.length} сканов`, 'success');
    } catch (e: any) {
      console.error('uploadOfflineFboSessionToDb error', e);
      showToast('Ошибка загрузки оффлайн-сессии: ' + (e?.message || 'неизвестно'), 'error');
    } finally {
      setOfflineFboUploadLoading(false);
    }
  };

  useEffect(() => {
    offlineFboSessionRef.current = offlineFboSession;
  }, [offlineFboSession]);

  useEffect(() => {
    refreshOfflineFboDeviceStats().catch(() => undefined);
  }, []);

  useEffect(() => {
    if (!showOfflineFboHistory) return;
    loadOfflineFboHistory().catch(() => undefined);
  }, [showOfflineFboHistory]);

  useEffect(() => {
    if (!currentSupply?.id || !fboOfflineMode) return;
    let cancelled = false;
    (async () => {
      const session = await readOfflineFboSessionFromDevice(currentSupply);
      if (cancelled) return;

      let nextSession = session;
      try {
        const { data: onlineBoxes } = await supabase
          .from('boxes')
          .select('name')
          .eq('supply_id', currentSupply.id)
          .is('deleted_at', null);
        const onlineMaxBoxNumber = getMaxNumericBoxName((onlineBoxes || []) as Array<{ name?: string | null }>);
        if (onlineMaxBoxNumber > Number(session?.base_box_number || 0)) {
          nextSession = {
            ...session,
            base_box_number: onlineMaxBoxNumber,
            updated_at: new Date().toISOString(),
          };
          writeOfflineFboSessionToDevice(nextSession).catch(() => undefined);
        }
      } catch (e) {
        console.error('offline FBO base box sync error', e);
      }

      offlineFboSessionRef.current = nextSession;
      setOfflineFboSession(nextSession);
      applyOfflineFboSessionToUi(nextSession, null);
      preloadOfflineFboIndexes(currentSupply.supplier_id).catch((e) => {
        console.error('offline FBO index warmup error', e);
      });
    })();
    return () => {
      cancelled = true;
    };
  }, [currentSupply?.id, currentSupply?.supplier_id, fboOfflineMode, applyOfflineFboSessionToUi]);

  useEffect(() => {
    if (!currentSupply?.id || fboOfflineMode) return;
    offlineFboSessionRef.current = null;
    setOfflineFboSession(null);
    fetchBoxesList(currentSupply.id);
    fetchSupplyStats(currentSupply.id);
    if (currentBox?.id) fetchBoxItems(currentBox.id);
  }, [currentSupply?.id, fboOfflineMode]);

  useEffect(() => {
    setOfflineFboValidation(null);
  }, [currentSupply?.id, fboOfflineMode, offlineFboSession?.updated_at]);

  useEffect(() => {
    if (!fboBoxesSupplierId && selectedSupplierId) {
      setFboBoxesSupplierId(selectedSupplierId);
    }
  }, [selectedSupplierId, fboBoxesSupplierId]);

  useEffect(() => {
    let cancelled = false;
    const run = async () => {
      if (!fboBoxesExcelFile) {
        setFboBoxesTotalLabels(0);
        setFboBoxesRangeFrom('1');
        setFboBoxesRangeTo('');
        return;
      }
      try {
        const buffer = await fboBoxesExcelFile.arrayBuffer();
        const rows = await readFirstSheetAsJson<Record<string, any>>(buffer, { defval: '' });
        const { codes } = parseFboBoxCodesFromRows(rows || []);
        if (cancelled) return;
        const total = codes.length;
        setFboBoxesTotalLabels(total);
        setFboBoxesRangeFrom('1');
        setFboBoxesRangeTo(total > 0 ? String(total) : '');
      } catch {
        if (!cancelled) {
          setFboBoxesTotalLabels(0);
          setFboBoxesRangeFrom('1');
          setFboBoxesRangeTo('');
        }
      }
    };
    run();
    return () => { cancelled = true; };
  }, [fboBoxesExcelFile]);

  const getWbSupplyStatusLabel = (s: any) => {
    const candidate = s?.status ?? s?.supplyStatus ?? s?.state ?? s?.statusName ?? s?.status_name ?? s?.currentStatus;
    if (candidate != null && candidate !== '') {
      if (typeof candidate === 'string' || typeof candidate === 'number') return String(candidate);
      if (typeof candidate === 'object') return String(candidate.name || candidate.value || candidate.status || candidate.state || JSON.stringify(candidate));
    }

    if (typeof s?.done === 'boolean') return s.done ? 'Принято (done=true)' : 'В работе (done=false)';
    if (typeof s?.isDone === 'boolean') return s.isDone ? 'Принято (isDone=true)' : 'В работе (isDone=false)';
    if (s?.closedAt || s?.closed_at) return 'Закрыта';
    if (s?.acceptanceAt || s?.acceptance_at) return 'Идет приемка';

    return '-';
  };

  const getWbSupplyStatusMeta = (s: any) => {
    const fields = [
      ['status', s?.status],
      ['supplyStatus', s?.supplyStatus],
      ['state', s?.state],
      ['statusName', s?.statusName ?? s?.status_name],
      ['done', s?.done ?? s?.isDone],
    ] as Array<[string, any]>;

    return fields
      .filter(([, v]) => v !== undefined && v !== null && v !== '')
      .map(([k, v]) => `${k}: ${typeof v === 'object' ? JSON.stringify(v) : String(v)}`)
      .join(' | ');
  };

  const parseFboBoxCodesFromRows = (rows: Record<string, any>[]) => {
    const first = rows[0] || {};
    const headers = Object.keys(first);
    if (!headers.length) return { codes: [] as string[], barcodeHeader: '' };

    const normalized = headers.map(h => ({ raw: h, n: String(h).trim().toLowerCase().replace(/\s+/g, '') }));
    const barcodeHeader = normalized.find(h => ['шккороба', 'шк', 'barcode', 'штрихкод', 'штрихкодкороба', 'barcodе'].includes(h.n))?.raw || headers[0];

    const codes = rows
      .map(r => String((r as any)[barcodeHeader] || '').trim())
      .filter(Boolean);

    return { codes, barcodeHeader };
  };

  // Supplies Functions
  const handleSyncSupplyBoxesFromExcel = async () => {
    try {
      if (!currentSupply?.id) return showToast('Сначала откройте поставку', 'error');
      if (!supplySyncExcelFile) return showToast('Загрузите Excel файл', 'error');

      const sizeError = ensureExcelFileSize(supplySyncExcelFile as File);
      if (sizeError) return showToast(sizeError, 'error');

      setSupplySyncLoading(true);
      const buffer = await supplySyncExcelFile.arrayBuffer();
      const rows = await readFirstSheetAsJson<Record<string, any>>(buffer, { defval: '' });
      if (!rows.length) return showToast('В файле нет строк', 'error');
      const rowLimitError = ensureExcelRowLimit(rows.length);
      if (rowLimitError) return showToast(rowLimitError, 'error');

      const { codes } = parseFboBoxCodesFromRows(rows);
      if (!codes.length) return showToast('Не найдены коды коробок в файле', 'error');

      const { data: supplyBoxes } = await supabase.from('boxes').select('id,name').eq('supply_id', currentSupply.id);
      const orderedBoxes = (supplyBoxes || [])
        .slice()
        .sort((a: any, b: any) => {
          const an = parseInt(String(a?.name || ''), 10);
          const bn = parseInt(String(b?.name || ''), 10);
          const av = Number.isFinite(an) ? an : Number.MAX_SAFE_INTEGER;
          const bv = Number.isFinite(bn) ? bn : Number.MAX_SAFE_INTEGER;
          return av - bv;
        });

      if (!orderedBoxes.length) return showToast('В поставке нет коробок для синхронизации', 'error');
      if (codes.length < orderedBoxes.length) return showToast(`В файле меньше кодов, чем коробок в поставке (${codes.length} < ${orderedBoxes.length})`, 'error');

      for (let i = 0; i < orderedBoxes.length; i++) {
        const box = orderedBoxes[i];
        const nextName = String(codes[i] || '').trim();
        if (!nextName) continue;
        await supabase.from('boxes').update({ name: nextName }).eq('id', box.id);
      }

      await fetchBoxesList(currentSupply.id);
      setSupplySyncOpen(false);
      setSupplySyncExcelFile(null);
      showToast('Коробки синхронизированы', 'success');
    } catch (e: any) {
      showToast(`Ошибка синхронизации: ${e?.message || e}`, 'error');
    } finally {
      setSupplySyncLoading(false);
    }
  };

  const handleGenerateFboBoxesLabelsFromExcel = async () => {
    await ensurePdfLibs();
    await ensureBwip();
    try {
      if (!fboBoxesSupplierId) return showToast('Сначала выберите поставщика для коробок FBO', 'error');
      if (!fboBoxesExcelFile) return showToast('Загрузите Excel файл', 'error');

      const sizeError = ensureExcelFileSize(fboBoxesExcelFile as File);
      if (sizeError) return showToast(sizeError, 'error');

      setFboBoxesGenerating(true);
      const buffer = await fboBoxesExcelFile.arrayBuffer();
      const rows = await readFirstSheetAsJson<Record<string, any>>(buffer, { defval: '' });
      if (!rows.length) return showToast('В файле нет строк', 'error');
      const rowLimitError = ensureExcelRowLimit(rows.length);
      if (rowLimitError) return showToast(rowLimitError, 'error');

      const { codes: allCodes, barcodeHeader } = parseFboBoxCodesFromRows(rows);
      if (!allCodes.length) return showToast(`Колонка "${barcodeHeader || 'первый столбец'}" пустая`, 'error');

      const totalAll = allCodes.length;
      const from = Math.max(1, Math.min(totalAll, parseInt(fboBoxesRangeFrom || '1', 10) || 1));
      const to = Math.max(from, Math.min(totalAll, parseInt(fboBoxesRangeTo || String(totalAll), 10) || totalAll));
      const codes = allCodes.slice(from - 1, to);

      if (!codes.length) return showToast('В выбранном диапазоне нет этикеток', 'error');

      const supplierName = suppliers.find(s => String(s.id) === String(fboBoxesSupplierId))?.name || 'Поставщик';
      const total = codes.length;

      const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: [58, 40] });
      const canvas = document.createElement('canvas');
      const layout = getWbLayoutPayloadFromEditor();

      let hasUnicodeFont = false;
      try {
        const res = await fetch('https://cdnjs.cloudflare.com/ajax/libs/pdfmake/0.1.66/fonts/Roboto/Roboto-Regular.ttf');
        if (res.ok) {
          const blob = await res.blob();
          const reader = new FileReader();
          const base64 = await new Promise<string>((resolve, reject) => {
            reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
            reader.onerror = () => reject(new Error('font read failed'));
            reader.readAsDataURL(blob);
          });
          doc.addFileToVFS('Roboto-normal.ttf', base64);
          doc.addFont('Roboto-normal.ttf', 'Roboto', 'normal');
          doc.setFont('Roboto', 'normal');
          hasUnicodeFont = true;
        }
      } catch {
        hasUnicodeFont = false;
      }

      const supplierLabel = hasUnicodeFont ? supplierName : supplierName.replace(/[^\x20-\x7E]/g, ' ').replace(/\s+/g, ' ').trim();
      const footerLabel = hasUnicodeFont ? 'ШК короба' : 'BOX BARCODE';

      for (let i = 0; i < total; i++) {
        if (i > 0) doc.addPage([58, 40], 'landscape');
        const code = codes[i];
        const isEan13 = /^\d{13}$/.test(code);

        bwipjs.toCanvas(canvas, {
          bcid: isEan13 ? 'ean13' : 'code128',
          text: code,
          scale: 3,
          height: 9,
          includetext: false,
          paddingwidth: 0,
          paddingheight: 0,
        });

        doc.setFontSize(layout.fboBoxes.numberFont);
        doc.text(`${i + 1}/${total}`, layout.fboBoxes.numberX, layout.fboBoxes.numberY, { align: 'center' });

        doc.setFontSize(layout.fboBoxes.supplierFont);
        const supplierText = doc.splitTextToSize(supplierLabel || 'Supplier', 54);
        doc.text(supplierText.slice(0, 1), layout.fboBoxes.supplierX, layout.fboBoxes.supplierY, { align: 'center' });

        doc.addImage(canvas.toDataURL('image/png'), 'PNG', layout.fboBoxes.barcodeX, layout.fboBoxes.barcodeY, layout.fboBoxes.barcodeW, layout.fboBoxes.barcodeH);

        doc.setFontSize(layout.fboBoxes.codeFont);
        doc.text(code, layout.fboBoxes.codeX, layout.fboBoxes.codeY, { align: 'center' });

        doc.setFontSize(layout.fboBoxes.footerFont);
        doc.text(footerLabel, layout.fboBoxes.footerX, layout.fboBoxes.footerY, { align: 'center' });
      }

      doc.save(`fbo_boxes_${supplierName.replace(/\s+/g, '_')}_${total}_${new Date().toISOString().slice(0, 10)}.pdf`);
      showToast(`Сформировано этикеток: ${total}`, 'success');
    } catch (e: any) {
      showToast('Ошибка генерации этикеток коробов: ' + (e?.message || 'неизвестно'), 'error');
    } finally {
      setFboBoxesGenerating(false);
    }
  };

  const fetchSupplyStats = async (supplyId: string) => {
    if (warehouseOfflineEnabled) {
      try {
        const snapshot = await getWarehouseOfflineSnapshotOrEmpty();
        setWarehouseOfflineSnapshot(snapshot);
        const boxes = getWarehouseOfflineSupplyBoxes(snapshot, supplyId);
        const snapshotSupply = (snapshot.fboSupplies || []).find((row: any) => String(row?.id || '') === String(supplyId));
        const savedItemsCount = snapshotSupply
          ? getOfflineSupplyItemsCount(snapshotSupply)
          : boxes.reduce((sum, box) => sum + getOfflineBoxItemsCount(box), 0);
        const scans = await warehouseOfflineClient.getFboScans().catch(() => ({ pending: [], synced: [], conflicts: [] }));
        const rows = [...((scans.pending || []) as any[]), ...((scans.synced || []) as any[])];
        const localItemsCount = rows.filter((row) => String(row?.supply_id || row?.supplyId || '') === String(supplyId)).length;
        const itemsCount = savedItemsCount + localItemsCount;
        setSupplyStats({ boxes: boxes.length, items: itemsCount });
        return;
      } catch (e) {
        setSupplyStats({ boxes: 0, items: 0 });
        return;
      }
    }

    // Optimized: Fetch active boxes and their item counts in one query
    const { data: boxes } = await supabase
        .from('boxes')
        .select('id, supply_items(count)')
        .eq('supply_id', supplyId)
        .is('deleted_at', null);

    const boxesCount = boxes?.length || 0;
    const itemsCount = boxes?.reduce((acc: number, box: any) => {
        return acc + (box.supply_items?.[0]?.count || 0);
    }, 0) || 0;

    setSupplyStats({ boxes: boxesCount, items: itemsCount });
  };

  const fetchSuppliesList = async () => {
    if (warehouseOfflineEnabled) {
      try {
        await loadWarehouseOfflineSnapshot(true);
      } catch (e: any) {
        setSuppliesList([]);
        showToast('Не удалось загрузить offline-поставки: ' + (e?.message || 'сервер недоступен'), 'error');
      }
      return;
    }

    if (!selectedSupplierId) {
      setSuppliesList([]);
      return;
    }

    const { data } = await supabase
      .from('supplies')
      .select('*, boxes(supply_items(count))')
      .eq('supplier_id', selectedSupplierId)
      .is('deleted_at', null)
      .order('created_at', { ascending: false });

    if (data) {
      const suppliesWithCounts = data.map((s: any) => {
        const total_items = s.boxes?.reduce((acc: number, box: any) => {
            return acc + (box.supply_items?.[0]?.count || 0);
        }, 0) || 0;
        return { ...s, total_items };
      });
      setSuppliesList(suppliesWithCounts);
    } else {
      setSuppliesList([]);
    }
  };

  const fetchBoxesList = async (supplyId: string) => {
    if (warehouseOfflineEnabled) {
      try {
        const snapshot = await getWarehouseOfflineSnapshotOrEmpty();
        setWarehouseOfflineSnapshot(snapshot);
        const scans = await warehouseOfflineClient.getFboScans().catch(() => ({ pending: [], synced: [], conflicts: [] }));
        const rows = [...((scans.pending || []) as any[]), ...((scans.synced || []) as any[])];
        const countsByBox = rows.reduce((acc: Record<string, number>, row: any) => {
          const boxId = String(row?.box_id || row?.boxId || '');
          if (boxId) acc[boxId] = (acc[boxId] || 0) + 1;
          return acc;
        }, {});
        setBoxesList(getWarehouseOfflineSupplyBoxes(snapshot, supplyId).map((box: any) => ({
          ...box,
          total_items: getOfflineBoxItemsCount(box) + (countsByBox[String(box.id)] || 0),
        })));
      } catch (e: any) {
        setBoxesList([]);
        showToast('Не удалось загрузить offline-коробки: ' + (e?.message || 'сервер недоступен'), 'error');
      }
      return;
    }

    const { data } = await supabase
        .from('boxes')
        .select('*, supply_items(count)')
        .eq('supply_id', supplyId)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });

    if (data) {
        const boxesWithCounts = data.map((box: any) => ({
            ...box,
            total_items: box.supply_items?.[0]?.count || 0
        }));
        setBoxesList(boxesWithCounts);
    } else {
        setBoxesList([]);
    }
  };

  const generateApiBoxesForCurrentSupply = async () => {
    if (!currentSupply) return;
    const count = Math.min(500, Math.max(1, parseInt(apiBoxCount || '1')));

    const supplier = suppliers.find(s => s.id === currentSupply.supplier_id);
    if (!supplier?.wb_api_token) {
      showToast('Нет WB API токена для генерации коробок', 'error');
      return;
    }

    setLoadingApiBoxes(true);
    try {
      const wbSupplyId = currentSupply.name;
      let boxNames: string[] = [];

      try {
        const res = await fetch(`https://marketplace-api.wildberries.ru/api/v3/supplies/${encodeURIComponent(wbSupplyId)}/trbx`, {
          method: 'POST',
          headers: {
            Authorization: supplier.wb_api_token.trim(),
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({ quantity: count })
        });

        if (res.ok) {
          const data = await res.json();
          const arr = data?.trbxes || data?.data || [];
          boxNames = (arr || []).map((x: any) => String(x?.barcode || x?.name || x)).filter(Boolean);
        }
      } catch (_) {}

      if (boxNames.length === 0) {
        boxNames = Array.from({ length: count }).map((_, i) => `${currentSupply.name}-BOX-${Date.now()}-${i + 1}`);
      }

      const payload = boxNames.map((name) => ({ name, supply_id: currentSupply.id }));
      const { error } = await supabase.from('boxes').insert(payload);
      if (error) throw error;

      await fetchBoxesList(currentSupply.id);
      await fetchSupplyStats(currentSupply.id);
      showToast(`Сгенерировано коробок: ${boxNames.length}`, 'success');
    } catch (e: any) {
      console.error(e);
      showToast(`Ошибка генерации коробок: ${e?.message || 'неизвестно'}`, 'error');
    } finally {
      setLoadingApiBoxes(false);
    }
  };

  const printCurrentSupplyBoxes58x40 = async () => {
    await ensurePdfLibs();
    await ensureBwip();
    if (!currentSupply) return;
    const { data: boxes } = await supabase
      .from('boxes')
      .select('name,created_at')
      .eq('supply_id', currentSupply.id)
      .is('deleted_at', null)
      .order('created_at', { ascending: false });

    if (!boxes || boxes.length === 0) {
      showToast('Нет коробок для печати', 'info');
      return;
    }

    const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: [58, 40] });
    const canvas = document.createElement('canvas');

    boxes.forEach((b: any, i: number) => {
      if (i > 0) doc.addPage([58, 40], 'landscape');
      const txt = String(b.name || 'BOX');
      bwipjs.toCanvas(canvas, {
        bcid: 'code128',
        text: txt,
        scale: 3,
        height: 11,
        includetext: false,
        paddingwidth: 0,
        paddingheight: 0,
      });
      doc.addImage(canvas.toDataURL('image/png'), 'PNG', 2.5, 7.5, 53, 15);
      doc.setFont('Helvetica', 'bold');
      doc.setFontSize(10.5);
      doc.text(txt, 29, 25.8, { align: 'center' });
      doc.setFontSize(8);
      doc.text(`Коробка • ${currentSupply.name}`, 29, 33.2, { align: 'center' });
    });

    const blobUrl = doc.output('bloburl');
    const preview = window.open('', 'SupplyBoxesPrintPreview', 'width=980,height=780');
    if (preview) {
      preview.document.write(`<html><head><title>Печать коробок 58x40</title></head><body style="margin:0;background:#f3f4f6;font-family:Arial,sans-serif;"><div style="padding:10px;display:flex;justify-content:space-between;align-items:center;background:#fff;border-bottom:1px solid #ddd;"><strong>Печать коробок 58x40</strong><button onclick="frames['pdfFrame'].focus();frames['pdfFrame'].print();" style="padding:8px 14px;border:none;background:#4f46e5;color:#fff;border-radius:8px;cursor:pointer;">Печать</button></div><iframe name="pdfFrame" src="${blobUrl}" style="width:100%;height:calc(100vh - 52px);border:0;"></iframe></body></html>`);
      preview.document.close();
    }
  };

  useEffect(() => {
    if (activeTab === 'supplies') fetchSuppliesList();
  }, [activeTab, selectedSupplierId, warehouseOfflineEnabled]);

  const handleSupplyScan = async (e: React.FormEvent) => {
    e.preventDefault();

    let input = supplyInput;
    setSupplyInput(''); // Clear immediately for speed

    if (/[\p{Script=Cyrillic}]/u.test(input)) {
       input = fixLayout(input);
       showToast('Раскладка исправлена', 'info');
    }

    // Handle Supplier QR Scan
    if (input.startsWith('SUPPLIER:')) {
      const supplierId = input.split(':')[1];
      const supplier = suppliers.find(s => s.id === supplierId);
      if (supplier) {
        switchTab('supplies');
        setSelectedSupplierId(supplierId);
        setSupplyStep('LIST');
        showToast(`Поставщик выбран: ${supplier.name}`, 'success');
      } else {
        showToast('Поставщик не найден', 'error');
      }
      return;
    }

    if (!input || !selectedSupplierId) {
      if (!selectedSupplierId) showToast('Выберите поставщика', 'error');
      return;
    }

    if (warehouseOfflineEnabled) {
      try {
        const snapshot = await getWarehouseOfflineSnapshotOrEmpty();
        const supplies = (snapshot.fboSupplies || []).map(normalizeWarehouseOfflineSupply);
        let supply = supplies.find((row) => String(row.name) === String(input) && String(row.supplier_id) === String(selectedSupplierId));

        if (!supply) {
          supply = {
            id: `offline-supply-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
            supplier_id: selectedSupplierId,
            name: input,
            status: 'active',
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
            total_items: 0,
          };
          const nextSnapshot = {
            ...snapshot,
            fboSupplies: [supply, ...(snapshot.fboSupplies || [])],
          };
          await saveWarehouseOfflineSnapshotState(nextSnapshot);
          showToast('Offline: поставка создана локально', 'success');
        } else {
          setWarehouseOfflineSnapshot(snapshot);
        }

        setCurrentSupply(supply);
        setSupplyStats({ boxes: getWarehouseOfflineSupplyBoxes(snapshot, supply.id).length, items: Number(supply.total_items || 0) });
        await fetchBoxesList(supply.id);
        setSupplyStep('SUPPLY');
      } catch (e: any) {
        showToast('Ошибка offline-поставки: ' + (e?.message || 'сервер недоступен'), 'error');
      }
      return;
    }

    // Check if supply exists
    const { data: existing } = await supabase.from('supplies').select('*').eq('name', input).maybeSingle();

    if (existing) {
      setCurrentSupply(existing);
      fetchBoxesList(existing.id);
      fetchSupplyStats(existing.id);
    } else {
      // Create new supply
      const { data: newSupply, error } = await supabase.from('supplies').insert([{
        name: input,
        supplier_id: selectedSupplierId
      }]).select().single();

      if (error) {
        showToast('Ошибка создания поставки: ' + error.message, 'error');
        return;
      }
      await logAction('Создание поставки', `Создана поставка: ${newSupply.name}`, currentEmployee?.id);
      setCurrentSupply(newSupply);
      await fetchSuppliesList();
      fetchBoxesList(newSupply.id);
      fetchSupplyStats(newSupply.id);
    }
    setSupplyStep('SUPPLY');
  };

  const handleBoxScan = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!boxInput || !currentSupply) return;

    let input = boxInput;
    setBoxInput(''); // Clear immediately for speed

    if (/[\p{Script=Cyrillic}]/u.test(input)) {
       input = fixLayout(input);
       showToast('Раскладка исправлена', 'info');
    }

    const normalized = String(input || '').trim();
    if (normalized === 'ACTION:GENERATE_BOX' || normalized === 'action:generate_box') {
      await createNextBoxInCurrentSupply();
      return;
    }

    if (warehouseOfflineEnabled) {
      try {
        const snapshot = await getWarehouseOfflineSnapshotOrEmpty();
        const boxes = getWarehouseOfflineSupplyBoxes(snapshot, currentSupply.id);
        let box = boxes.find((row) => String(row.name) === String(input));

        if (!box) {
          box = {
            id: `offline-box-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
            supply_id: currentSupply.id,
            name: input,
            created_at: new Date().toISOString(),
          };
          const nextSnapshot = {
            ...snapshot,
            fboBoxes: [box, ...(snapshot.fboBoxes || [])],
          };
          await saveWarehouseOfflineSnapshotState(nextSnapshot);
          showToast(`Offline: создана коробка ${box.name}`, 'success');
        } else {
          setWarehouseOfflineSnapshot(snapshot);
        }

        setCurrentBox(box);
        setBoxItems([]);
        await fetchBoxesList(currentSupply.id);
        await fetchSupplyStats(currentSupply.id);
        setSupplyStep('BOX');
      } catch (e: any) {
        showToast('Ошибка offline-коробки: ' + (e?.message || 'сервер недоступен'), 'error');
      }
      return;
    }

    if (fboOfflineMode) {
      const existing = (offlineFboSession?.boxes || []).find((box) => String(box.name) === String(input));
      if (existing) {
        setCurrentBox(existing);
        applyOfflineFboSessionToUi(offlineFboSession || buildEmptyOfflineFboSession(currentSupply), existing.id);
      } else {
        const newBox: SupplyBox = {
          id: `offline-box-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
          name: input,
          supply_id: currentSupply.id,
          created_at: new Date().toISOString(),
        };
        updateOfflineFboSession((session) => ({ ...session, boxes: [newBox, ...(session.boxes || [])] }), newBox.id);
        setCurrentBox(newBox);
        setBoxItems([]);
        showToast(`Оффлайн: создана коробка ${newBox.name}`, 'success');
      }
      setSupplyStep('BOX');
      return;
    }

    // Check if box exists in this supply
    const { data: existing } = await supabase.from('boxes').select('*').eq('name', input).eq('supply_id', currentSupply.id).maybeSingle();

    if (existing) {
      setCurrentBox(existing);
      fetchBoxItems(existing.id);
    } else {
      // Create new box
      const { data: newBox, error } = await supabase.from('boxes').insert([{
        name: input,
        supply_id: currentSupply.id
      }]).select().single();

      if (error) {
        showToast('Ошибка создания коробки: ' + error.message, 'error');
        return;
      }
      await logAction('Создание коробки', `Создана коробка: ${newBox.name} в поставке ${currentSupply.name}`, currentEmployee?.id);
      setCurrentBox(newBox);
      fetchBoxItems(newBox.id);
    }
    setSupplyStep('BOX');
    fetchBoxesList(currentSupply.id);
  };

  const createNextBoxInCurrentSupply = async () => {
    if (!currentSupply?.id) {
      return;
    }

    if (warehouseOfflineEnabled) {
      try {
        const snapshot = await getWarehouseOfflineSnapshotOrEmpty();
        const existingBoxes = getWarehouseOfflineSupplyBoxes(snapshot, currentSupply.id);
        const used = new Set(existingBoxes.map((b: any) => parseInt(String(b?.name || '').trim(), 10)).filter((n: number) => Number.isFinite(n) && n > 0));
        let nextNumber = 1;
        while (used.has(nextNumber)) nextNumber += 1;
        const nextName = String(nextNumber);
        const newBox: SupplyBox = {
          id: `offline-box-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
          name: nextName,
          supply_id: currentSupply.id,
          created_at: new Date().toISOString(),
        };
        await saveWarehouseOfflineSnapshotState({
          ...snapshot,
          fboBoxes: [newBox, ...(snapshot.fboBoxes || [])],
        });
        setCurrentBox(newBox);
        setSupplyStep('BOX');
        setScannedItem(null);
        if (itemInputRef.current) itemInputRef.current.value = '';
        if (honestSignInputRef.current) honestSignInputRef.current.value = '';
        setBoxItems([]);
        await fetchBoxesList(currentSupply.id);
        await fetchSupplyStats(currentSupply.id);
        showToast(`Offline: создана коробка №${nextName}`, 'success');
      } catch (e: any) {
        showToast('Ошибка создания offline-коробки: ' + (e?.message || 'сервер недоступен'), 'error');
      }
      return;
    }

    if (fboOfflineMode) {
      const session = offlineFboSessionRef.current && offlineFboSessionRef.current.supply_id === currentSupply.id
        ? offlineFboSessionRef.current
        : buildEmptyOfflineFboSession(currentSupply);
      const existingBoxes = session?.boxes || [];
      const sessionMaxNumber = getMaxNumericBoxName(existingBoxes as Array<{ name?: string | null }>);
      const nextNumber = Math.max(Number(session?.base_box_number || 0), sessionMaxNumber) + 1;
      const nextName = String(nextNumber);
      const newBox: SupplyBox = {
        id: `offline-box-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        name: nextName,
        supply_id: currentSupply.id,
        created_at: new Date().toISOString(),
      };
      updateOfflineFboSession((session) => ({ ...session, boxes: [newBox, ...(session.boxes || [])] }), newBox.id);
      setCurrentBox(newBox);
      setSupplyStep('BOX');
      setScannedItem(null);
      if (itemInputRef.current) itemInputRef.current.value = '';
      if (honestSignInputRef.current) honestSignInputRef.current.value = '';
      setBoxItems([]);
      showToast(`Оффлайн: создана коробка №${nextName}`, 'success');
      return;
    }

    const { data: existingBoxes } = await supabase.from('boxes').select('name').eq('supply_id', currentSupply.id).is('deleted_at', null);
    const used = new Set((existingBoxes || []).map((b: any) => parseInt(String(b?.name || '').trim(), 10)).filter((n: number) => Number.isFinite(n) && n > 0));
    let nextNumber = 1;
    while (used.has(nextNumber)) nextNumber += 1;
    const nextName = String(nextNumber);
    const { data: newBox, error } = await supabase.from('boxes').insert([{ name: nextName, supply_id: currentSupply.id }]).select().single();
    if (error) {
      showToast('Ошибка создания коробки: ' + error.message, 'error');
      return;
    }
    await logAction('Создание коробки', `Создана коробка: ${newBox.name} в поставке ${currentSupply.name} (QR генерация)`, currentEmployee?.id);
    setCurrentBox(newBox);
    setSupplyStep('BOX');
    setScannedItem(null);
    if (itemInputRef.current) itemInputRef.current.value = '';
    if (honestSignInputRef.current) honestSignInputRef.current.value = '';
    await fetchBoxesList(currentSupply.id);
    showToast(`Создана коробка №${nextName}`, 'success');
  };

  const finishCurrentBoxAndReturn = async () => {
    if (fboOfflineMode && offlineFboSessionRef.current) {
      if (offlineFboSessionWriteTimeoutRef.current) {
        window.clearTimeout(offlineFboSessionWriteTimeoutRef.current);
        offlineFboSessionWriteTimeoutRef.current = null;
      }
      await writeOfflineFboSessionToDevice(offlineFboSessionRef.current);
    }
    setSupplyStep('SUPPLY');
    setCurrentBox(null);
    setScannedItem(null);
    if (itemInputRef.current) itemInputRef.current.value = '';
    if (honestSignInputRef.current) honestSignInputRef.current.value = '';
    showToast('Коробка завершена, можно выбрать или создать следующую', 'success');
  };

  const handleDeleteSupplyItem = async (itemId: string) => {
    if (!itemId) return;
    if (!window.confirm('Удалить этот скан из коробки?')) return;

    try {
      if (fboOfflineMode && currentSupply) {
        updateOfflineFboSession((session) => ({
          ...session,
          items: (session.items || []).filter((item) => item.id !== itemId),
        }), currentBox?.id || null);
        showToast('Скан удалён из оффлайн-сессии', 'success');
        return;
      }

      const { error } = await softDeleteWithActor('supply_items', itemId);
      if (error) throw error;

      if (currentBox?.id) {
        await fetchBoxItems(currentBox.id);
      }
      if (currentSupply?.id) {
        await fetchSupplyStats(currentSupply.id);
        await fetchBoxesList(currentSupply.id);
      }

      showToast('Скан удалён', 'success');
    } catch (e: any) {
      showToast('Ошибка удаления скана: ' + (e?.message || 'неизвестно'), 'error');
    }
  };

  const openSupplyProductsModal = async () => {
    if (!currentSupply?.id) return;
    try {
      setSupplyProductsLoading(true);
      setShowSupplyProductsModal(true);

      const pageSize = 1000;
      const allBoxes: any[] = [];
      let boxesFrom = 0;
      while (true) {
        const { data: boxesChunk, error: boxesError } = await supabase
          .from('boxes')
          .select('id,name,deleted_at')
          .eq('supply_id', currentSupply.id)
          .is('deleted_at', null)
          .range(boxesFrom, boxesFrom + pageSize - 1);
        if (boxesError) throw boxesError;
        const chunk = boxesChunk || [];
        allBoxes.push(...chunk);
        if (chunk.length < pageSize) break;
        boxesFrom += pageSize;
      }

      const boxIds = allBoxes.map((b: any) => b.id).filter(Boolean);
      if (!boxIds.length) {
        setSupplyProductsRows([]);
        return;
      }

      const allItems: any[] = [];
      for (let i = 0; i < boxIds.length; i += 200) {
        const boxIdsChunk = boxIds.slice(i, i + 200);
        let itemsFrom = 0;
        while (true) {
          const { data: itemsChunk, error: itemsError } = await supabase
            .from('supply_items')
            .select('id, box_id, product_id, honest_sign_code, created_at, deleted_at, product:products(id,name,wb_sku,barcode,size,color)')
            .in('box_id', boxIdsChunk)
            .is('deleted_at', null)
            .range(itemsFrom, itemsFrom + pageSize - 1);
          if (itemsError) throw itemsError;
          const chunk = itemsChunk || [];
          allItems.push(...chunk);
          if (chunk.length < pageSize) break;
          itemsFrom += pageSize;
        }
      }

      const { data: wbCacheRows, error: wbCacheError } = await supabase
        .from('wb_products_cache')
        .select('nm_id, product_json')
        .eq('supplier_id', currentSupply.supplier_id)
        .limit(10000);
      if (wbCacheError) throw wbCacheError;

      const wbByBarcode = new Map<string, any>();
      const wbByNm = new Map<string, any>();
      (wbCacheRows || []).forEach((row: any) => {
        const card = row?.product_json || {};
        const nmId = String(row?.nm_id || card?.nmID || card?.nmId || '').trim();
        if (nmId) wbByNm.set(nmId, card);
        const topBarcode = String(card?.barcode || card?.skus?.[0] || '').trim();
        if (topBarcode) wbByBarcode.set(topBarcode, card);
        const sizes = Array.isArray(card?.sizes) ? card.sizes : [];
        sizes.forEach((size: any) => {
          const skus = Array.isArray(size?.skus) ? size.skus : [];
          skus.forEach((sku: any) => {
            const key = String(sku || '').trim();
            if (key) wbByBarcode.set(key, card);
          });
        });
      });

      const grouped = new Map<string, { image?: string; article: string; title: string; sizes: Record<string, number>; sizeBarcodes: Record<string, Set<string>>; totalQty: number }>();
      allItems.forEach((item: any) => {
        const p = item?.product || {};
        const qty = 1;
        const barcode = String(p?.barcode || '').trim();
        const wbSku = String(p?.wb_sku || '').trim();
        const wb = wbByBarcode.get(barcode) || wbByBarcode.get(wbSku) || wbByNm.get(wbSku) || null;
        const article = String(wb?.vendorCode || wb?.article || p?.wb_sku || p?.barcode || '—');
        const title = String(wb?.title || wb?.name || p?.name || 'Товар');
        const firstPhoto = (Array.isArray(wb?.photos) && wb.photos[0]) || (Array.isArray(wb?.mediaFiles) && wb.mediaFiles[0]) || '';
        const rawImage = String(wb?.photoUrl || wb?.image || wb?.image_url || firstPhoto?.big || firstPhoto?.tm || firstPhoto || '').trim();
        const image = /^https?:\/\//i.test(rawImage) ? rawImage : '';
        const size = String(p?.size || wb?.size || 'Без размера');
        const key = String(wb?.nmID || wb?.nmId || p?.wb_sku || p?.barcode || `${title}-${article}`);
        if (!grouped.has(key)) grouped.set(key, { image, article, title, sizes: {}, sizeBarcodes: {}, totalQty: 0 });
        const row = grouped.get(key)!;
        row.sizes[size] = (row.sizes[size] || 0) + qty;
        if (!row.sizeBarcodes[size]) row.sizeBarcodes[size] = new Set<string>();
        if (barcode) row.sizeBarcodes[size].add(barcode);
        row.totalQty += qty;
      });

      const rows = Array.from(grouped.entries()).map(([key, row]) => ({
        key,
        nmId: String(key || ''),
        image: row.image,
        article: row.article,
        title: row.title,
        sizesText: Object.entries(row.sizes).map(([size, qty]) => `${size}: ${qty}`).join(', '),
        sizeBarcodeLines: Object.entries(row.sizes).map(([size, qty]) => {
          const barcodes = Array.from(row.sizeBarcodes[size] || []).filter(Boolean);
          const barcodeText = barcodes.length ? barcodes.join(', ') : 'без ШК';
          return `${size}: ${qty} , ШК: ${barcodeText}`;
        }),
        totalQty: row.totalQty,
      }));

      setSupplyProductsRows(rows);
    } catch (e) {
      console.error('openSupplyProductsModal error', e);
      setSupplyProductsRows([]);
      showToast('Ошибка загрузки товаров поставки', 'error');
    } finally {
      setSupplyProductsLoading(false);
    }
  };

  const refreshSupplyProductsPhotos = async () => {
    try {
      if (!currentSupply?.supplier_id || !supplyProductsRows.length) return;
      setSupplyProductsPhotoLoading(true);
      const { data, error } = await supabase
        .from('wb_products_cache')
        .select('supplier_id, nm_id, product_json')
        .eq('supplier_id', currentSupply.supplier_id)
        .limit(10000);
      if (error) throw error;

      const photoByNm: Record<string, string> = {};
      const photoByBarcode: Record<string, string> = {};
      const photoByVendor: Record<string, string> = {};
      (data || []).forEach((row: any) => {
        const p = row?.product_json || {};
        const nm = String(row?.nm_id || p?.nmID || p?.nmId || '').trim();
        const barcode = String(p?.barcode || p?.skus?.[0] || '').trim();
        const vendor = String(p?.vendorCode || p?.article || '').trim().toLowerCase();
        const first = (Array.isArray(p?.photos) && p.photos[0]) || (Array.isArray(p?.mediaFiles) && p.mediaFiles[0]) || '';
        let src = typeof first === 'string' ? first : (first?.big || first?.tm || first?.c246x328 || '');
        src = String(p?.photoUrl || p?.image || p?.image_url || src || '').trim();
        if (src && src.startsWith('//')) src = `https:${src}`;
        if (!/^https?:\/\//i.test(src)) return;
        if (nm) photoByNm[`${String(row?.supplier_id)}__${nm}`] = src;
        if (barcode) photoByBarcode[`${String(row?.supplier_id)}__${barcode}`] = src;
        if (vendor) photoByVendor[`${String(row?.supplier_id)}__${vendor}`] = src;
      });

      let updated = 0;
      setSupplyProductsRows((prev) => (prev || []).map((r: any) => {
        const supplierKey = String(currentSupply?.supplier_id || '');
        const byNm = photoByNm[`${supplierKey}__${String(r?.nmId || r?.key || '')}`] || '';
        const byBarcode = photoByBarcode[`${supplierKey}__${String(r?.article || '').trim()}`] || '';
        const byVendor = photoByVendor[`${supplierKey}__${String(r?.article || '').trim().toLowerCase()}`] || '';
        const src = byNm || byBarcode || byVendor || '';
        if (src && src !== r.image) {
          updated += 1;
          return { ...r, image: src };
        }
        return r;
      }));
      showToast(`Фото обновлены: ${updated}`, 'success');
    } catch (e: any) {
      showToast('Ошибка обновления фото: ' + (e?.message || 'неизвестно'), 'error');
    } finally {
      setSupplyProductsPhotoLoading(false);
    }
  };


  const getFboPalletImage = (card: any) => {
    const firstPhoto = (Array.isArray(card?.photos) && card.photos[0]) || (Array.isArray(card?.mediaFiles) && card.mediaFiles[0]) || '';
    let src = String(card?.photoUrl || card?.image || card?.image_url || firstPhoto?.big || firstPhoto?.c516x688 || firstPhoto?.c246x328 || firstPhoto?.tm || firstPhoto || '').trim();
    if (src.startsWith('//')) src = 'https:' + src;
    return /^https?:\/\//i.test(src) ? src : '';
  };

  const createFboPalletId = (prefix: string) => {
    const randomId = typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2);
    return prefix + '-' + randomId;
  };

  const parseFboPalletSnapshot = (value: any) => {
    try {
      const parsed = typeof value === 'string' ? JSON.parse(value) : value;
      return {
        sessions: Array.isArray(parsed?.sessions) ? parsed.sessions as FboPalletSession[] : [],
        warehouses: Array.isArray(parsed?.warehouses) ? parsed.warehouses as FboPalletWarehouse[] : [],
        supplies: Array.isArray(parsed?.supplies) ? parsed.supplies as FboPalletSupply[] : [],
        pallets: Array.isArray(parsed?.pallets) ? parsed.pallets as FboPallet[] : [],
        items: Array.isArray(parsed?.items) ? parsed.items as FboPalletItem[] : [],
      };
    } catch {
      return { sessions: [] as FboPalletSession[], warehouses: [] as FboPalletWarehouse[], supplies: [] as FboPalletSupply[], pallets: [] as FboPallet[], items: [] as FboPalletItem[] };
    }
  };

  const loadFboPalletSnapshot = async () => {
    const { data, error } = await supabase
      .from('app_settings')
      .select('value')
      .eq('key', 'fbo_pallet_collection_v1')
      .maybeSingle();
    if (error) throw error;
    return parseFboPalletSnapshot(data?.value);
  };

  const saveFboPalletSnapshot = async (snapshot: FboPalletSnapshot) => {
    const { error } = await supabase.from('app_settings').upsert([{
      key: 'fbo_pallet_collection_v1',
      value: JSON.stringify(snapshot),
    }], { onConflict: 'key' });
    if (error) throw error;
  };

  const applyFboPalletSnapshotToState = (snapshot: FboPalletSnapshot, supplierId = '') => {
    const normalizedSupplierId = String(supplierId || '').trim();
    const sessions = snapshot.sessions
      .filter((session) => !session.deleted_at && (!normalizedSupplierId || String(session.supplier_id) === normalizedSupplierId))
      .sort((a, b) => String(b.created_at || '').localeCompare(String(a.created_at || '')));
    const sessionIds = new Set(sessions.map((session) => String(session.id)));
    const pallets = snapshot.pallets
      .filter((pallet) => !pallet.deleted_at && (!normalizedSupplierId || String(pallet.supplier_id) === normalizedSupplierId) && sessionIds.has(String(pallet.session_id)))
      .sort((a, b) => Number(a.pallet_number || 0) - Number(b.pallet_number || 0));
    const palletIds = new Set(pallets.map((pallet) => String(pallet.id)));
    const items = snapshot.items
      .filter((item) => !item.deleted_at && (!normalizedSupplierId || String(item.supplier_id) === normalizedSupplierId) && palletIds.has(String(item.pallet_id)))
      .sort((a, b) => String(b.created_at || '').localeCompare(String(a.created_at || '')));

    setFboPalletSessions(sessions);
    const warehouses = snapshot.warehouses
      .filter((warehouse) => !warehouse.deleted_at && (!normalizedSupplierId || String(warehouse.supplier_id) === normalizedSupplierId))
      .sort((a, b) => String(a.created_at || '').localeCompare(String(b.created_at || '')));
    setFboPalletWarehouses(warehouses);
    const supplies = snapshot.supplies
      .filter((supply) => !supply.deleted_at && (!normalizedSupplierId || String(supply.supplier_id) === normalizedSupplierId))
      .sort((a, b) => String(a.created_at || '').localeCompare(String(b.created_at || '')));
    setFboPalletSupplies(supplies);

    // Resolve the selected warehouse via a functional updater (reads latest state),
    // capture the resolved id, then pick a supply that belongs to that warehouse.
    let resolvedWarehouseId = '';
    setFboPalletSelectedWarehouseId((current) => {
      resolvedWarehouseId = current && warehouses.some((warehouse) => String(warehouse.id) === String(current))
        ? current
        : (warehouses[0]?.id || '');
      return resolvedWarehouseId;
    });
    setFboPalletSelectedSupplyId((current) => {
      const inWarehouse = supplies.filter((supply) => String(supply.warehouse_id) === String(resolvedWarehouseId));
      if (current && inWarehouse.some((supply) => String(supply.id) === String(current))) return current;
      return inWarehouse[0]?.id || '';
    });

    setFboPallets(pallets);
    setFboPalletItems(items);
  };

  const getFboPalletActiveSession = async (supplierId: string) => {
    const snapshot = await loadFboPalletSnapshot();
    const existing = snapshot.sessions
      .filter((session) => String(session.supplier_id) === String(supplierId) && session.status === 'active' && !session.deleted_at)
      .sort((a, b) => String(b.created_at || '').localeCompare(String(a.created_at || '')))[0];
    if (existing?.id) return { session: existing, snapshot };

    const now = new Date().toISOString();
    const session: FboPalletSession = {
      id: createFboPalletId('fbo-pallet-session'),
      supplier_id: supplierId,
      status: 'active',
      created_by: currentEmployee?.id || null,
      created_at: now,
      updated_at: now,
      deleted_at: null,
    };
    const nextSnapshot = { ...snapshot, sessions: [session, ...snapshot.sessions] };
    await saveFboPalletSnapshot(nextSnapshot);
    return { session, snapshot: nextSnapshot };
  };

  const fetchFboPalletData = async (supplierId = fboPalletSupplierId) => {
    const normalizedSupplierId = String(supplierId || '').trim();
    setFboPalletLoading(true);
    try {
      const snapshot = await loadFboPalletSnapshot();
      applyFboPalletSnapshotToState(snapshot, normalizedSupplierId);
    } catch (e: any) {
      console.error('fetchFboPalletData error', e);
      showToast('Ошибка загрузки паллет FBO: ' + (e?.message || 'неизвестно'), 'error');
    } finally {
      setFboPalletLoading(false);
    }
  };

  const loadFboPalletProducts = async (supplierId: string) => {
    const normalizedSupplierId = String(supplierId || '').trim();
    if (!normalizedSupplierId) {
      setFboPalletProducts([]);
      return;
    }

    setFboPalletProductsLoading(true);
    try {
      const pageSize = 500;
      const rows: any[] = [];
      let from = 0;
      while (true) {
        const { data, error } = await supabase
          .from('wb_products_cache')
          .select('nm_id, product_json')
          .eq('supplier_id', normalizedSupplierId)
          .range(from, from + pageSize - 1);
        if (error) throw error;
        const chunk = data || [];
        rows.push(...chunk);
        if (chunk.length < pageSize) break;
        from += pageSize;
      }

      const options: FboPalletProductOption[] = [];
      rows.forEach((row: any) => {
        const card = row?.product_json || {};
        const nmId = String(row?.nm_id || card?.nmID || card?.nmId || '').trim();
        const title = String(card?.title || card?.name || 'Товар WB').trim();
        const vendorCode = String(card?.vendorCode || card?.article || '').trim();
        const brand = String(card?.brand || getWbCharacteristicValue(card, ['бренд']) || '').trim();
        const category = String(card?.subjectName || card?.subject || card?.category || '').trim();
        const color = String(getWbCharacteristicValue(card, ['цвет']) || card?.color || '').trim();
        const photo = getFboPalletImage(card);
        const sizes = Array.isArray(card?.sizes) && card.sizes.length ? card.sizes : [{ techSize: '', skus: card?.skus || card?.barcodes || [] }];

        sizes.forEach((size: any, index: number) => {
          const skus = Array.isArray(size?.skus) && size.skus.length ? size.skus : [card?.barcode || card?.skus?.[0] || ''];
          const barcode = String(skus[0] || '').trim();
          options.push({
            key: [nmId, String(size?.techSize || ''), barcode, index].join('__'),
            nm_id: nmId,
            barcode,
            vendor_code: vendorCode,
            title,
            brand,
            category,
            size: String(size?.techSize || '').trim(),
            color,
            photo_url: photo,
            product_json: { ...card, selectedSize: size, selectedBarcode: barcode },
          });
        });
      });

      setFboPalletProducts(options);
    } catch (e: any) {
      console.error('loadFboPalletProducts error', e);
      setFboPalletProducts([]);
      showToast('Ошибка загрузки товаров WB для паллет: ' + (e?.message || 'неизвестно'), 'error');
    } finally {
      setFboPalletProductsLoading(false);
    }
  };

