  // Removed localStorage effect for telegramBotToken

  const generateSupplyExcel = async (supply: Supply) => {
    // 1. Fetch all boxes
    const { data: boxes, error: boxesError } = await supabase
      .from('boxes')
      .select('id, name')
      .eq('supply_id', supply.id);

    if (boxesError) throw boxesError;

    const boxMap = new Map(boxes?.map(b => [b.id, b.name]) || []);
    const boxIds = boxes?.map(b => b.id) || [];

    // 2. Fetch all items
    let items: any[] = [];
    if (boxIds.length > 0) {
      const { data, error: itemsError } = await supabase
        .from('supply_items')
        .select('*, product:products(barcode)')
        .in('box_id', boxIds);

      if (itemsError) throw itemsError;
      items = data || [];
    }

    // 3. Group and Count
    // Key: "ProductBarcode|BoxName" -> Count
    const counts = new Map<string, number>();

    items.forEach(item => {
      const productData = Array.isArray(item.product) ? item.product[0] : item.product;
      const barcode = productData?.barcode || 'UNKNOWN';
      const boxName = boxMap.get(item.box_id) || 'UNKNOWN';
      const key = `${barcode}|${boxName}`;
      counts.set(key, (counts.get(key) || 0) + 1);
    });

    // 4. Format Data
    let rows = Array.from(counts.entries()).map(([key, count]) => {
      const [barcode, boxName] = key.split('|');
      return {
        'Баркод товара': barcode,
        'Кол-во товаров': count,
        'ШК короба': boxName,
        'Срок годности': ''
      };
    });

    // 5. Create workbook blob
    return await createWorkbookBlob([
      {
        name: 'Поставка',
        rows,
        headers: ['Баркод товара', 'Кол-во товаров', 'ШК короба', 'Срок годности'],
        widths: [20, 15, 20, 15],
      },
    ]);
  };

  const handleDownloadExcel = async () => {
    if (!currentSupply) return;
    try {
      const blob = await generateSupplyExcel(currentSupply);

      const supplierName = suppliers.find(s => s.id === currentSupply.supplier_id)?.name || 'Unknown';
      const dateStr = new Date().toLocaleDateString('ru-RU').replace(/\./g, '-');
      const fileName = `${supplierName}_${dateStr}.xlsx`;

      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = fileName;
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (error: any) {
      showToast('Ошибка генерации файла: ' + error.message, 'error');
    }
  };

