  // Settings Logic
  const handleSaveSetting = async (key: string, value: string) => {
    try {
      const { error } = await supabase
        .from('app_settings')
        .upsert({ key, value });

      if (error) throw error;
      showToast('Настройка сохранена', 'success');
    } catch (e) {
      console.error('Error saving setting:', e);
      showToast('Ошибка при сохранении', 'error');
    }
  };

  useEffect(() => {
    const fetchSettings = async () => {
        const { data } = await supabase
          .from('app_settings')
          .select('key, value')
          .in('key', ['telegram_bot_token', 'telegram_reception_bot_token', 'telegram_login_logs_bot_token', 'telegram_bot_token_file', 'backup_bot_token', 'database_backup_logs']);

        if (data) {
            data.forEach(setting => {
                if (setting.key === 'telegram_bot_token') setTelegramBotToken(setting.value);
                if (setting.key === 'telegram_reception_bot_token') setTelegramReceptionBotToken(setting.value);
                if (setting.key === 'telegram_login_logs_bot_token') setTelegramBotTokenFile(setting.value);
                if (setting.key === 'backup_bot_token') setBackupBotToken(setting.value);
                if (setting.key === 'database_backup_logs') {
                    try {
                        const parsed = typeof setting.value === 'string' ? JSON.parse(setting.value) : setting.value;
                        if (Array.isArray(parsed)) {
                            setDatabaseLogs(parsed);
                        }
                    } catch (e) {
                        console.error('Failed to parse database logs', e);
                    }
                }
            });
        }
    };
    fetchSettings();
  }, []);

  const handleSendTelegram = (e: React.FormEvent) => {
    e.preventDefault();
    const selectedToken = selectedBotForManual === 'reception'
      ? telegramReceptionBotToken
      : selectedBotForManual === 'file'
        ? backupBotToken
        : telegramBotToken;

    if (!selectedToken || !telegramSupplierId || (!telegramMessage && !telegramFile)) {
      showToast('Заполните все обязательные поля', 'error');
      return;
    }

    const supplier = suppliers.find(s => s.id === telegramSupplierId);
    if (!supplier || !supplier.telegram_chat_id) {
      showToast('У выбранного поставщика нет Chat ID', 'error');
      return;
    }

    // Capture data for background sending
    const currentMessage = telegramMessage;
    const currentFile = telegramFile;
    const currentToken = selectedToken;
    const chatId = supplier.telegram_chat_id;

    // Optimistic UI update
    showToast('Сообщение отправлено', 'success');
    setTelegramMessage('');
    setTelegramFile(null);
    if (telegramFileRef.current) telegramFileRef.current.value = '';

    // Send in background
    (async () => {
      try {
        const formData = new FormData();
        formData.append('chat_id', chatId);

        let endpoint = `https://api.telegram.org/bot${currentToken}/sendMessage`;

        if (currentFile) {
          endpoint = `https://api.telegram.org/bot${currentToken}/sendDocument`;
          formData.append('document', currentFile);
          if (currentMessage) formData.append('caption', currentMessage);
        } else {
          formData.append('text', currentMessage);
        }

        const response = await fetch(endpoint, {
          method: 'POST',
          body: formData
        });

        const data = await response.json();
        if (!data.ok) throw new Error(data.description);
      } catch (error: any) {
        console.error('Background Telegram send failed:', error);
      }
    })();
  };

  const handleSendTelegramMenu = async () => {
    const selectedToken = selectedBotForManual === 'reception'
      ? telegramReceptionBotToken
      : selectedBotForManual === 'file'
        ? backupBotToken
        : telegramBotToken;

    if (!selectedToken || !telegramSupplierId) {
      showToast('Выберите бота и поставщика', 'error');
      return;
    }

    const supplier = suppliers.find(s => s.id === telegramSupplierId);
    if (!supplier || !supplier.telegram_chat_id) {
      showToast('У выбранного поставщика нет Chat ID', 'error');
      return;
    }

    try {
      // 1) Clear old keyboard first
      const clearResp = await fetch(`https://api.telegram.org/bot${selectedToken}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          chat_id: supplier.telegram_chat_id,
          text: 'Обновляю меню…',
          reply_markup: { remove_keyboard: true }
        })
      });
      const clearData = await clearResp.json();
      if (!clearData.ok) throw new Error(clearData.description || 'Telegram API error (remove keyboard)');

      // 2) New main menu button
      const response = await fetch(`https://api.telegram.org/bot${selectedToken}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          chat_id: supplier.telegram_chat_id,
          text: 'Меню SkladPro',
          reply_markup: {
            keyboard: [[{ text: '📦 Показать активные поставки' }]],
            resize_keyboard: true,
            one_time_keyboard: false,
          }
        })
      });

      const data = await response.json();
      if (!data.ok) throw new Error(data.description || 'Telegram API error');

      // 3) Immediately send active supplies list with download links per supply
      const { data: activeSupplies, error: suppliesError } = await supabase
        .from('supplies')
        .select('id, name, status, created_at')
        .eq('supplier_id', telegramSupplierId)
        .is('deleted_at', null)
        .not('status', 'in', '(done,completed,closed)')
        .order('created_at', { ascending: false })
        .limit(15);
      if (suppliesError) throw suppliesError;

      const { data: allFiles } = await supabase
        .from('print_files')
        .select('name, url, supplier_id, created_at')
        .eq('supplier_id', telegramSupplierId)
        .order('created_at', { ascending: false })
        .limit(500);

      const files = (allFiles || []) as Array<{ name?: string; url?: string }>;
      const suppliesRows = (activeSupplies || []) as Array<{ id: string; name?: string; status?: string }>;

      for (const s of suppliesRows) {
        const supplyName = String(s?.name || 'Поставка').trim();
        const filesForSupply = files.filter((f) => String(f?.name || '').toLowerCase().includes(supplyName.toLowerCase()));
        const fbsFile = filesForSupply.find((f) => /fbs|лист\s*подбора|picking/i.test(String(f?.name || '')));
        const groupFile = filesForSupply.find((f) => /груп|group/i.test(String(f?.name || '')));
        const stickerFile = filesForSupply.find((f) => /стикер|sticker|этикет/i.test(String(f?.name || '')));

        const row1: Array<{ text: string; url: string }> = [];
        if (fbsFile?.url) row1.push({ text: '📥 FBS лист', url: String(fbsFile.url) });
        if (groupFile?.url) row1.push({ text: '📥 Групп лист', url: String(groupFile.url) });
        const row2: Array<{ text: string; url: string }> = [];
        if (stickerFile?.url) row2.push({ text: '🏷 Стикеры', url: String(stickerFile.url) });

        const inline_keyboard = [row1, row2].filter((r) => r.length > 0);
        const text = `📦 ${supplyName}${s?.status ? `\nСтатус: ${s.status}` : ''}`;

        await fetch(`https://api.telegram.org/bot${selectedToken}/sendMessage`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            chat_id: supplier.telegram_chat_id,
            text,
            ...(inline_keyboard.length ? { reply_markup: { inline_keyboard } } : {})
          })
        });
      }

      if (!suppliesRows.length) {
        await fetch(`https://api.telegram.org/bot${selectedToken}/sendMessage`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            chat_id: supplier.telegram_chat_id,
            text: 'Активные поставки не найдены.'
          })
        });
      }

      showToast('Меню и список активных поставок отправлены в Telegram', 'success');
    } catch (error: any) {
      showToast(`Ошибка отправки меню: ${error?.message || 'Unknown error'}`, 'error');
    }
  };

