  const checkBarcodeExists = async (barcode: string, supplierId: string) => {
    if (!barcode || !supplierId) return false;
    const { data } = await supabase.from('products').select('id').eq('barcode', barcode).eq('supplier_id', supplierId).maybeSingle();
    return !!data;
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSupplierId) return;

    // Check barcode
    if (newProduct.barcode) {
      const exists = await checkBarcodeExists(newProduct.barcode, selectedSupplierId);
      if (exists) {
        showToast(`Товар с баркодом ${newProduct.barcode} уже существует у этого поставщика!`, 'error');
        return;
      }
    }

    const { error } = await supabase.from('products').insert([{
      ...newProduct,
      supplier_id: selectedSupplierId
    }]);

    if (error) showToast('Ошибка: ' + error.message, 'error');
    else {
      showToast('Товар успешно добавлен', 'success');
      setShowAddProductModal(false);
      setNewProduct({ name: '', wb_sku: '', barcode: '', size: '', color: '' });
    }
  };

  const handleDeleteProduct = (product: Product) => {
    setProductToDelete(product);
  };

  const confirmDeleteProduct = async () => {
    if (!productToDelete) return;

    // Delete related supply items first to avoid FK constraint error
    await supabase.from('supply_items').update({ deleted_at: new Date().toISOString() }).eq('product_id', productToDelete.id);

    const { error } = await softDeleteWithActor('products', productToDelete.id);
    if (error) showToast('Ошибка удаления: ' + error.message, 'error');
    else showToast('Товар удален', 'success');
    setProductToDelete(null);
  };

  const getValue = (row: any, keys: string[]) => {
    const rowKeys = Object.keys(row);
    for (const k of keys) {
      const foundKey = rowKeys.find(rk => rk.toLowerCase().trim() === k.toLowerCase().trim());
      if (foundKey) return row[foundKey];
    }
    return '';
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !selectedSupplierId) return;
    const fileSizeError = ensureExcelFileSize(file);
    if (fileSizeError) {
      showToast(fileSizeError, 'error');
      return;
    }

    const buff = await file.arrayBuffer();
    const data = await readFirstSheetAsJson<any>(buff) as any[];
    const rowLimitError = ensureExcelRowLimit(data.length);
    if (rowLimitError) {
      showToast(rowLimitError, 'error');
      return;
    }

    if (!data.length) {
      showToast('Файл пустой', 'error');
      return;
    }

    const productsColumnsError = ensureRequiredColumns(Object.keys(data[0] || {}), [
      { label: 'Barcode', aliases: ['Barcode', 'Баркод', 'Штрихкод'] },
    ]);
    if (productsColumnsError) {
      showToast(productsColumnsError, 'error');
      return;
    }

    try {
      const productsToInsert: any[] = [];
      let duplicatesCount = 0;

      // Fetch all existing barcodes to check against
      const { data: existingProducts } = await supabase.from('products').select('barcode');
      const existingBarcodes = new Set(existingProducts?.map(p => p.barcode).filter(Boolean));

      for (const row of data) {
        const barcode = getValue(row, ['Barcode', 'Баркод', 'barcode', 'Штрихкод']);

        if (barcode && existingBarcodes.has(String(barcode))) {
          duplicatesCount++;
          continue;
        }

        productsToInsert.push({
          supplier_id: selectedSupplierId,
          name: getValue(row, ['Name', 'Наименование', 'name', 'Название']) || 'Unknown',
          wb_sku: getValue(row, ['SKU', 'WB Артикул', 'sku', 'Артикул', 'Артикул WB']),
          barcode: String(barcode || ''),
          size: String(getValue(row, ['Size', 'Размер', 'size', 'Tech Size', 'Размер товара']) || ''),
          color: getValue(row, ['Color', 'Цвет', 'color'])
        });
      }

      if (productsToInsert.length > 0) {
        const { data: insertedData, error } = await supabase
          .from('products')
          .insert(productsToInsert)
          .select('id');

        if (error) {
          showToast('Ошибка импорта: ' + error.message, 'error');
        } else {
          setLastImportedIds(insertedData.map(d => d.id));
          showToast(`Импортировано ${productsToInsert.length} товаров. Пропущено дубликатов: ${duplicatesCount}`, 'success');
        }
      } else {
        showToast(`Нет новых товаров для импорта. Пропущено дубликатов: ${duplicatesCount}`, 'info');
      }

      // Reset file input
      if (fileInputRef.current) fileInputRef.current.value = '';
    } catch (error: any) {
      showToast('Ошибка чтения файла: ' + (error?.message || 'неизвестно'), 'error');
    }
  };

  const handleSyncProductsFromWbCache = async () => {
    if (syncingProductsFromWb) return;

    setSyncingProductsFromWb(true);
    try {
      const { data: suppliersData, error: suppliersError } = await supabase.from('suppliers').select('id');
      if (suppliersError) throw suppliersError;

      const validSuppliers = new Set((suppliersData || []).map((s: any) => s.id));

      const pageSize = 200;
      let from = 0;
      const sourceRows: Array<{ supplier_id: string; product_json: any }> = [];

      while (true) {
        const { data, error } = await supabase
          .from('wb_products_cache')
          .select('supplier_id, product_json')
          .range(from, from + pageSize - 1);

        if (error) throw error;
        const chunk = data || [];
        sourceRows.push(...chunk as any);
        if (chunk.length < pageSize) break;
        from += pageSize;
      }

      const extractColor = (p: any) => {
        const arr = Array.isArray(p?.characteristics) ? p.characteristics : [];
        for (const c of arr) {
          const n = String(c?.name || c?.Name || '').toLowerCase();
          if (n === 'цвет') {
            const v = c?.value ?? c?.Value;
            return Array.isArray(v) ? String(v[0] || '').trim() : String(v || '').trim();
          }
        }
        return '';
      };

      const nextProducts: Array<{ supplier_id: string; name: string; wb_sku: string; barcode: string; size: string; color: string }> = [];

      sourceRows.forEach((row) => {
        const p = row.product_json || {};
        const supplierId = row.supplier_id;
        if (!validSuppliers.has(supplierId)) return;

        const name = String(p.title || '').trim() || 'Unknown';
        const wbSku = String(p.vendorCode || p.nmID || '').trim();
        const color = extractColor(p);
        const sizes = Array.isArray(p.sizes) && p.sizes.length ? p.sizes : [{ techSize: '', wbSize: '', skus: [''] }];

        sizes.forEach((sz: any) => {
          const size = String(sz?.techSize || sz?.wbSize || '').trim();
          const skus = Array.isArray(sz?.skus) && sz.skus.length ? sz.skus : [''];
          skus.forEach((sku: any) => {
            nextProducts.push({
              supplier_id: supplierId,
              name,
              wb_sku: wbSku,
              barcode: String(sku || '').trim(),
              size,
              color,
            });
          });
        });
      });

      const deduped: typeof nextProducts = [];
      const seen = new Set<string>();
      for (const p of nextProducts) {
        const key = `${p.supplier_id}|${p.wb_sku}|${p.barcode}|${p.size}|${p.color}`.toLowerCase();
        if (seen.has(key)) continue;
        seen.add(key);
        deduped.push(p);
      }

      const { error: clearError } = await supabase.from('products').delete().not('id', 'is', null);
      if (clearError) throw clearError;

      const insertChunk = 500;
      for (let i = 0; i < deduped.length; i += insertChunk) {
        const batch = deduped.slice(i, i + insertChunk);
        const { error } = await supabase.from('products').insert(batch);
        if (error) throw error;
      }

      showToast(`Синхронизация завершена: загружено ${deduped.length} товаров из Товары WB`, 'success');
      setLastImportedIds([]);
      await fetchProducts();
    } catch (error: any) {
      showToast(`Ошибка синхронизации из Товары WB: ${error?.message || 'неизвестно'}`, 'error');
    } finally {
      setSyncingProductsFromWb(false);
    }
  };

  const handleUndoImport = async () => {
    if (lastImportedIds.length === 0) return;
    if (!window.confirm('Отменить последний импорт? Это удалит все добавленные товары.')) return;

    const batchSize = 100;
    let hasError = false;

    for (let i = 0; i < lastImportedIds.length; i += batchSize) {
      const batch = lastImportedIds.slice(i, i + batchSize);
      const { error } = await supabase.from('products').delete().in('id', batch);
      if (error) {
        showToast('Ошибка отмены: ' + error.message, 'error');
        hasError = true;
        break;
      }
    }

    if (!hasError) {
      showToast('Импорт отменен', 'success');
      setLastImportedIds([]);
    }
  };

  const handleToggleSupplyLockList = async (supply: Supply) => {
    if (supply.status === 'closed') {
        setSupplyToUnlock(supply);
        setShowUnlockConfirmation(true);
    } else {
        // Lock immediately
        const { error } = await supabase
          .from('supplies')
          .update({ status: 'closed' })
          .eq('id', supply.id);

        if (error) {
          showToast('Ошибка обновления статуса: ' + error.message, 'error');
        } else {
          setSuppliesList(suppliesList.map(s => s.id === supply.id ? { ...s, status: 'closed' } : s));
          if (currentSupply && currentSupply.id === supply.id) {
            setCurrentSupply({ ...currentSupply, status: 'closed' });
          }
          showToast('Поставка заблокирована', 'success');
        }
    }
  };

  const confirmUnlockSupply = async () => {
    if (!supplyToUnlock) return;

    const { error } = await supabase
      .from('supplies')
      .update({ status: 'active' })
      .eq('id', supplyToUnlock.id);

    if (error) {
      showToast('Ошибка обновления статуса: ' + error.message, 'error');
    } else {
      setSuppliesList(suppliesList.map(s => s.id === supplyToUnlock.id ? { ...s, status: 'active' } : s));
      if (currentSupply && currentSupply.id === supplyToUnlock.id) {
        setCurrentSupply({ ...currentSupply, status: 'active' });
      }
      showToast('Поставка разблокирована', 'success');
      setShowUnlockConfirmation(false);
      setSupplyToUnlock(null);
    }
  };

  // Reception State
  const [receptionStep, setReceptionStep] = useState<'LIST' | 'EDIT'>('LIST');
  const [receptionSupplierId, setReceptionSupplierId] = useState('');
  const [receptionPhotos, setReceptionPhotos] = useState<{id: string, url: string, quantity: string}[]>([]);
  const [sendingReception, setSendingReception] = useState(false);
  const [receptionsList, setReceptionsList] = useState<any[]>([]);
  const [receptionsListAll, setReceptionsListAll] = useState<any[]>([]);
  const [receptionMetaMap, setReceptionMetaMap] = useState<Record<string, { count: number; quantity: number; preview?: string }>>({});
  const [receptionMetaRefreshing, setReceptionMetaRefreshing] = useState(false);
  const [currentReception, setCurrentReception] = useState<any | null>(null);
  const [receptionDate, setReceptionDate] = useState(new Date().toISOString().split('T')[0]);
  const fileInputRefReception = useRef<HTMLInputElement>(null);

  // Telegram Reception Token
  const [telegramReceptionBotToken, setTelegramReceptionBotToken] = useState('');
  const [isReceptionTokenLocked, setIsReceptionTokenLocked] = useState(true);

  // Fetch global settings (tokens)
  useEffect(() => {
    const fetchSettings = async () => {
      const { data, error } = await supabase
        .from('app_settings')
        .select('key, value')
        .in('key', ['telegram_bot_token', 'telegram_reception_bot_token']);

      if (data && !error) {
        const botToken = data.find(s => s.key === 'telegram_bot_token')?.value;
        const receptionToken = data.find(s => s.key === 'telegram_reception_bot_token')?.value;

        if (botToken) setTelegramBotToken(botToken);
        if (receptionToken) setTelegramReceptionBotToken(receptionToken);
      }
    };
    fetchSettings();
  }, []);

  // Removed localStorage effect for telegramReceptionBotToken

  const persistReceptionMeta = useCallback(async (next: Record<string, { count: number; quantity: number; preview?: string }>) => {
    try {
      const raw = JSON.stringify(next || {});
      const { data: updatedRows, error: updateError } = await supabase
        .from('app_settings')
        .update({ value: raw })
        .eq('key', 'reception_meta_v1')
        .select('key');
      if (updateError) throw updateError;
      if (!updatedRows || updatedRows.length === 0) {
        const { error: insertError } = await supabase.from('app_settings').insert({ key: 'reception_meta_v1', value: raw });
        if (insertError) throw insertError;
      }
    } catch (e) {
      console.error('Failed to persist reception meta:', e);
    }
  }, []);

  useEffect(() => {
    const loadReceptionMeta = async () => {
      try {
        const { data } = await supabase.from('app_settings').select('value').eq('key', 'reception_meta_v1').limit(1);
        const row = Array.isArray(data) ? data[0] : null;
        const parsed = row?.value ? (typeof row.value === 'string' ? JSON.parse(row.value) : row.value) : {};
        if (parsed && typeof parsed === 'object') setReceptionMetaMap(parsed as Record<string, { count: number; quantity: number; preview?: string }>);
      } catch {
        // noop
      }
    };
    loadReceptionMeta();
  }, []);

  const updateReceptionMetaByPhotos = useCallback((receptionId: string, photos: Array<{ url?: string; quantity?: string }> = []) => {
    setReceptionMetaMap((prev) => {
      const quantity = photos.reduce((sum, p: any) => sum + (parseInt(String(p?.quantity || '0'), 10) || 0), 0);
      const next = {
        ...(prev || {}),
        [receptionId]: {
          count: photos.length,
          quantity,
          preview: photos[0]?.url || prev?.[receptionId]?.preview || '',
        },
      };
      persistReceptionMeta(next);
      return next;
    });
  }, [persistReceptionMeta]);

  const fillReceptionMetaCounts = useCallback(async (receptionIds: string[]) => {
    if (!receptionIds.length) return;
    try {
      const { data } = await supabase.from('receptions').select('id, photos').in('id', receptionIds as any);
      if (!data) return;
      setReceptionMetaMap((prev) => {
        const next = { ...(prev || {}) };
        (data || []).forEach((row: any) => {
          const photos = Array.isArray(row?.photos) ? row.photos : [];
          const quantity = photos.reduce((sum: number, p: any) => sum + (parseInt(String(p?.quantity || '0'), 10) || 0), 0);
          next[String(row.id)] = {
            count: photos.length,
            quantity,
            preview: photos[0]?.url || next[String(row.id)]?.preview || '',
          };
        });
        persistReceptionMeta(next);
        return next;
      });
    } catch (e) {
      console.error('Failed to fetch reception counts:', e);
    }
  }, [persistReceptionMeta]);

  const fetchReceptions = async (supplierId?: string) => {
    const limit = supplierId ? 80 : 120;

    const run = async (selectClause: string) => {
      let q = supabase
        .from('receptions')
        .select(selectClause)
        .is('deleted_at', null)
        .order('created_at', { ascending: false })
        .limit(limit);
      if (supplierId) q = q.eq('supplier_id', supplierId);
      return q;
    };

    // 1) Preferred fast query with stats + supplier name
    let result = await run('id, supplier_id, status, created_at, updated_at, photos_count, items_quantity, supplier:suppliers(name)');

    // 2) Fallback without stats columns
    if (result.error) {
      result = await run('id, supplier_id, status, created_at, updated_at, supplier:suppliers(name)');
    }

    // 3) Hard fallback without relation join (in case FK/relation issue)
    if (result.error) {
      result = await run('id, supplier_id, status, created_at, updated_at');
    }

    if (result.error) {
      console.error('Error fetching receptions:', result.error);
      showToast('Ошибка загрузки истории приемок: ' + (result.error.message || 'неизвестно'), 'error');
      setReceptionsList([]);
      if (!supplierId) setReceptionsListAll([]);
      return;
    }

    const rows = result.data || [];
    if (!supplierId) {
      setReceptionsListAll(rows);
      setReceptionsList(rows);
      return;
    }

    if (receptionsListAll.length > 0) {
      setReceptionsList(receptionsListAll.filter((r: any) => String(r.supplier_id) === String(supplierId)));
    }
    setReceptionsList(rows);
  };

  useEffect(() => {
    if (activeTab === 'reception') fetchReceptions(receptionSupplierId);
  }, [activeTab, receptionSupplierId]);

  const refreshVisibleReceptionMeta = useCallback(async () => {
    const ids = (receptionsList || []).map((r: any) => String(r.id || '')).filter(Boolean).slice(0, 25);
    if (!ids.length) return;
    setReceptionMetaRefreshing(true);
    try {
      const patch: Record<string, { count: number; quantity: number; preview?: string }> = {};
      // Single query for all visible receptions instead of one request per id (N+1).
      const { data: rows } = await supabase.from('receptions').select('id, photos').in('id', ids);
      (rows || []).forEach((row: any) => {
        const id = String(row?.id || '');
        if (!id) return;
        const photos = Array.isArray(row?.photos) ? row.photos : [];
        const quantity = photos.reduce((sum: number, p: any) => sum + (parseInt(String(p?.quantity || '0'), 10) || 0), 0);
        patch[id] = { count: photos.length, quantity, preview: photos[0]?.url || '' };
      });

      if (Object.keys(patch).length > 0) {
        setReceptionMetaMap((prev) => {
          const next = { ...(prev || {}), ...patch };
          persistReceptionMeta(next);
          return next;
        });
      }
    } finally {
      setReceptionMetaRefreshing(false);
    }
  }, [receptionsList, persistReceptionMeta]);

  const handleCreateReception = async () => {
    if (!receptionSupplierId) {
      showToast('Выберите поставщика', 'error');
      return;
    }

    let { data, error } = await supabase.from('receptions').insert([{
      supplier_id: receptionSupplierId,
      status: 'active',
      photos: [],
      photos_count: 0,
      items_quantity: 0,
    } as any]).select('*, supplier:suppliers(name)').single();

    if (error && String((error as any)?.message || '').includes('photos_count')) {
      const fallback = await supabase.from('receptions').insert([{
        supplier_id: receptionSupplierId,
        status: 'active',
        photos: []
      }]).select('*, supplier:suppliers(name)').single();
      data = fallback.data as any;
      error = fallback.error as any;
    }

    if (error) {
      showToast('Ошибка создания: ' + error.message, 'error');
      return;
    }

    setCurrentReception(data);
    setReceptionPhotos([]);
    setReceptionDate(data?.created_at ? new Date(data.created_at).toISOString().split('T')[0] : new Date().toISOString().split('T')[0]);
    setReceptionStep('EDIT');
    updateReceptionMetaByPhotos(data.id, [] as any);
    await logAssemblyChange('receptions', 'create', null, data);
  };

  const handleOpenReception = async (reception: any) => {
    // Open immediately with whatever is already in list (including photos when supplier selected)
    setCurrentReception(reception);
    setReceptionSupplierId(reception.supplier_id);
    setReceptionDate(reception?.created_at ? new Date(reception.created_at).toISOString().split('T')[0] : new Date().toISOString().split('T')[0]);
    setReceptionPhotos(Array.isArray(reception?.photos) ? reception.photos : []);
    setReceptionStep('EDIT');

    // Refresh full object in background
    const { data } = await supabase
      .from('receptions')
      .select('*, supplier:suppliers(name)')
      .eq('id', reception.id)
      .maybeSingle();

    if (data) {
      setCurrentReception(data);
      setReceptionPhotos(data.photos || []);
      setReceptionDate(data?.created_at ? new Date(data.created_at).toISOString().split('T')[0] : new Date().toISOString().split('T')[0]);
      updateReceptionMetaByPhotos(String(data.id), Array.isArray(data.photos) ? data.photos : []);
    }
  };

  const calcReceptionStats = (photos: Array<{ quantity?: string }> = []) => {
    const photosCount = photos.length;
    const itemsQuantity = photos.reduce((sum: number, p: any) => sum + (parseInt(String(p?.quantity || '0'), 10) || 0), 0);
    return { photosCount, itemsQuantity };
  };

  const handleSaveReception = async () => {
    if (!currentReception) return;

    const normalizedReceptionDate = receptionDate && /^\d{4}-\d{2}-\d{2}$/.test(receptionDate)
      ? new Date(`${receptionDate}T12:00:00`).toISOString()
      : currentReception.created_at;

    const stats = calcReceptionStats(receptionPhotos as any);

    let { error } = await supabase.from('receptions').update({
      photos: receptionPhotos,
      photos_count: stats.photosCount,
      items_quantity: stats.itemsQuantity,
      created_at: normalizedReceptionDate,
      updated_at: new Date().toISOString()
    } as any).eq('id', currentReception.id);

    if (error && String((error as any)?.message || '').includes('photos_count')) {
      const fallback = await supabase.from('receptions').update({
        photos: receptionPhotos,
        created_at: normalizedReceptionDate,
        updated_at: new Date().toISOString()
      }).eq('id', currentReception.id);
      error = fallback.error;
    }

    if (error) {
      showToast('Ошибка сохранения: ' + error.message, 'error');
    } else {
      const before = { ...currentReception };
      const after = { ...currentReception, created_at: normalizedReceptionDate, photos: receptionPhotos, photos_count: stats.photosCount, items_quantity: stats.itemsQuantity };
      setCurrentReception((prev: any) => prev ? { ...prev, created_at: normalizedReceptionDate, photos: receptionPhotos } : prev);
      setReceptionsList(prev => prev.map(r => r.id === currentReception.id ? { ...r, created_at: normalizedReceptionDate, photos: receptionPhotos } : r));
      updateReceptionMetaByPhotos(currentReception.id, receptionPhotos as any);
      await logAssemblyChange('receptions', 'update', before, after);
      showToast('Сохранено', 'success');
    }
  };

  const handleReceptionPhoto = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files);

      files.forEach(file => {
        const reader = new FileReader();
        reader.onload = (e) => {
          if (e.target?.result) {
            setReceptionPhotos(prev => {
              const newPhotos = [...prev, {
                id: Math.random().toString(36).substr(2, 9),
                url: e.target!.result as string,
                quantity: ''
              }];
              // Auto-save if we have a current reception
              if (currentReception) {
                // We can't easily await here inside the callback without more logic,
                // but the user can click "Save" or "Finish".
                // Or we can trigger a save effect. For now, manual save or finish is fine.
              }
              return newPhotos;
            });
          }
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const sendCurrentReceptionToTelegram = async (supplierInput?: any) => {
    if (receptionPhotos.length === 0) {
      showToast('Добавьте хотя бы одно фото', 'error');
      return;
    }

    const supplier = supplierInput || suppliers.find(s => s.id === receptionSupplierId) || currentReception?.supplier;
    if (!supplier) {
      showToast('Поставщик не найден', 'error');
      return;
    }

    let chatId = supplier.telegram_chat_id;
    if (!chatId) {
      const { data } = await supabase.from('suppliers').select('telegram_chat_id').eq('id', receptionSupplierId).single();
      chatId = data?.telegram_chat_id;
    }

    if (!chatId) {
      showToast('У поставщика нет Telegram Chat ID', 'error');
      return;
    }

    let token = String(telegramReceptionBotToken || '').trim();
    if (!token) {
        const { data } = await supabase.from('app_settings').select('value').eq('key', 'telegram_reception_bot_token').maybeSingle();
        if (data?.value) {
            token = String(data.value).trim();
            setTelegramReceptionBotToken(token);
        }
    }
    if (!token) token = String(telegramBotToken || '').trim();
    if (!token) {
      showToast('Не настроен токен бота для приемки', 'error');
      return;
    }

    let totalQuantity = 0;
    for (const photo of receptionPhotos) {
      const qty = parseInt(photo.quantity) || 0;
      totalQuantity += qty;
      const res = await fetch(photo.url);
      const blob = await res.blob();
      await telegramService.sendPhoto(token, String(chatId), blob, `Количество: ${qty} шт`);
    }

    const receptionDateText = receptionDate && /^\d{4}-\d{2}-\d{2}$/.test(receptionDate)
      ? new Date(`${receptionDate}T12:00:00`).toLocaleDateString('ru-RU')
      : new Date().toLocaleDateString('ru-RU');
    const text = `Приемка товаров на склад\nПоставщик: ${supplier.name}\nДата: ${receptionDateText}\nИтого товара: ${totalQuantity} шт`;
    await telegramService.sendMessage(token, String(chatId), text);
  };

  const handleFinishReception = async () => {
    if (receptionPhotos.length === 0) {
      showToast('Добавьте хотя бы одно фото', 'error');
      return;
    }

    const supplier = suppliers.find(s => s.id === receptionSupplierId) || currentReception?.supplier;
    if (!supplier) {
      showToast('Поставщик не найден', 'error');
      return;
    }

    setSendingReception(true);
    try {
      // 1. Save to DB first
      const normalizedReceptionDate = receptionDate && /^\d{4}-\d{2}-\d{2}$/.test(receptionDate)
        ? new Date(`${receptionDate}T12:00:00`).toISOString()
        : currentReception.created_at;

      const stats = calcReceptionStats(receptionPhotos as any);

      let closeRes = await supabase.from('receptions').update({
        photos: receptionPhotos,
        photos_count: stats.photosCount,
        items_quantity: stats.itemsQuantity,
        status: 'closed',
        created_at: normalizedReceptionDate,
        updated_at: new Date().toISOString()
      } as any).eq('id', currentReception.id);

      if (closeRes.error && String((closeRes.error as any)?.message || '').includes('photos_count')) {
        closeRes = await supabase.from('receptions').update({
          photos: receptionPhotos,
          status: 'closed',
          created_at: normalizedReceptionDate,
          updated_at: new Date().toISOString()
        }).eq('id', currentReception.id);
      }

      updateReceptionMetaByPhotos(currentReception.id, receptionPhotos as any);

      await logAction('Приемка', `Завершена приемка от ${supplier.name}`, currentEmployee?.id);
      await logAssemblyChange('receptions', 'update', currentReception, {
        ...currentReception,
        status: 'closed',
        created_at: normalizedReceptionDate,
        photos: receptionPhotos,
        photos_count: stats.photosCount,
        items_quantity: stats.itemsQuantity,
        supplier_name: supplier.name,
      });

      // 2. Send to Telegram
      await sendCurrentReceptionToTelegram(supplier);

      showToast('Приемка завершена и отправлена', 'success');
      setReceptionPhotos([]);
      setReceptionSupplierId('');
      setCurrentReception(null);
      setReceptionDate(new Date().toISOString().split('T')[0]);
      setReceptionStep('LIST');
      fetchReceptions();
    } catch (error: any) {
      showToast('Ошибка: ' + error.message, 'error');
    } finally {
      setSendingReception(false);
    }
  };

  const handleOpenSupplierHistory = async (supplier: Supplier, type: 'supplies' | 'receptions' = 'supplies') => {
    setHistorySupplier(supplier);
    setHistoryType(type);
    setShowSupplierHistory(true);

    if (type === 'supplies') {
      const { data } = await supabase.from('supplies').select('*').eq('supplier_id', supplier.id).order('created_at', { ascending: false });

      if (data) {
        // Single server-side aggregation instead of an N+1 (boxes + supply_items per supply).
        const countsBySupply = new Map<string, number>();
        const { data: counts, error: countsError } = await supabase
          .rpc('supplier_supply_item_counts', { p_supplier_id: supplier.id });
        if (!countsError && Array.isArray(counts)) {
          for (const row of counts as Array<{ supply_id: string; total_items: number }>) {
            countsBySupply.set(String(row.supply_id), Number(row.total_items) || 0);
          }
        }
        setHistorySupplies(data.map((s) => ({ ...s, total_items: countsBySupply.get(String(s.id)) || 0 })));
      } else {
        setHistorySupplies([]);
      }
    } else {
      const { data } = await supabase
        .from('receptions')
        .select('id, supplier_id, status, created_at, updated_at')
        .eq('supplier_id', supplier.id)
        .order('created_at', { ascending: false })
        .limit(150);
      setHistoryReceptions(data || []);
    }
  };

