  const hasAssemblyButtonAccess = useCallback((buttonId: string) => {
    if (!currentEmployee) return false;

    const roleKey = normalizeRoleKey(currentEmployee.role || currentEmployee.login);
    if (roleKey === 'admin') return true;
    if (!assemblyButtonAccessLoaded) return false;

    const cfg = assemblyButtonAccess[buttonId] || {};
    const byEmployee = cfg.employees?.[String(currentEmployee.id || '')];
    if (byEmployee === 'allow') return true;
    if (byEmployee === 'deny') return false;

    const byRole = cfg.roles?.[roleKey];
    if (byRole === 'allow') return true;
    if (byRole === 'deny') return false;

    return true;
  }, [assemblyButtonAccess, assemblyButtonAccessLoaded, currentEmployee]);

  const getCalendarEmployeeRule = useCallback((employee: any): AccessRule => {
    const cfg = assemblyButtonAccess['cw_calendar_employee_pick'] || {};
    const byEmployee = cfg.employees?.[String(employee?.id || '')];
    if (byEmployee === 'allow' || byEmployee === 'deny' || byEmployee === 'inherit') return byEmployee;

    const employeeRoleKey = normalizeRoleKey(employee?.role || employee?.login);
    const byRole = cfg.roles?.[employeeRoleKey];
    if (byRole === 'allow' || byRole === 'deny' || byRole === 'inherit') return byRole;

    return 'inherit';
  }, [assemblyButtonAccess]);

