  const downloadUploadedRawSourceFile = async (item: any) => {
    const b64 = String(item?.summary_json?.source_file_base64 || '').trim();
    const srcName = String(item?.summary_json?.source_file_name || item?.file_name || 'source_report.xlsx');
    const sourceBucket = String(item?.summary_json?.source_file_bucket || '').trim();
    const sourcePath = String(item?.summary_json?.source_file_path || '').trim();

    try {
      if (sourceBucket && sourcePath) {
        const { data, error } = await supabase.storage.from(sourceBucket).download(sourcePath);
        if (!error && data) {
          const url = URL.createObjectURL(data);
          const a = document.createElement('a');
          a.href = url;
          a.download = srcName.endsWith('.xlsx') || srcName.endsWith('.xls') ? srcName : `${srcName}.xlsx`;
          document.body.appendChild(a);
          a.click();
          a.remove();
          URL.revokeObjectURL(url);
          return;
        }
      }

      if (b64) {
        const bytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0));
        const blob = new Blob([bytes], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = srcName.endsWith('.xlsx') || srcName.endsWith('.xls') ? srcName : `${srcName}.xlsx`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        URL.revokeObjectURL(url);
        return;
      }

      const rows = Array.isArray(item?.rows_json) ? item.rows_json : [];
      if (!rows.length) {
        showToast('Для этой записи нет исходных строк отчёта', 'error');
        return;
      }

      await downloadJsonRowsAsExcel(rows, srcName, 'WB Report Raw');
      showToast('Файл восстановлен из данных БД и скачан', 'success');
    } catch (e) {
      console.error('downloadUploadedRawSourceFile error', e);
      showToast('Не удалось скачать исходный файл', 'error');
    }
  };

  const deleteUploadedRawHistoryItem = async (id: string, fileName?: string) => {
    if (!id) return;
    const label = String(fileName || 'этот WB отчёт');
    const ok = window.confirm(`Удалить из истории WB: ${label}?`);
    if (!ok) return;
    try {
      const { error } = await supabase.from('analytics_upload_reports_raw').delete().eq('id', id);
      if (error) throw error;
      await loadUploadedRawReportHistory(uploadedSelectedSupplierId);
      showToast('WB отчёт удалён из отдельной истории', 'success');
    } catch (e) {
      console.error('deleteUploadedRawHistoryItem error', e);
      showToast('Не удалось удалить WB отчёт', 'error');
    }
  };

  const loadUploadedReportHistory = async (supplierId: string) => {
    if (!supplierId) return;
    try {
      setUploadedHistoryLoading(true);
      const { data, error } = await supabase
        .from('analytics_upload_history')
        .select('id, supplier_id, supplier_name, file_name, summary_json, created_at')
        .eq('supplier_id', supplierId)
        .order('created_at', { ascending: false })
        .limit(200);
      if (error) throw error;
      const sorted = (Array.isArray(data) ? data : []).sort((a: any, b: any) => {
        const da = new Date(a?.summary_json?.period_start || a?.created_at || 0).getTime();
        const db = new Date(b?.summary_json?.period_start || b?.created_at || 0).getTime();
        return da - db;
      });
      setUploadedHistory(sorted);
    } catch (e) {
      console.error('loadUploadedReportHistory error', e);
      setUploadedHistory([]);
    } finally {
      setUploadedHistoryLoading(false);
    }
  };

  const recalcAnalyticsToPayWithoutAcquiring = (arr: any[]) => {
    return (Array.isArray(arr) ? arr : []).map((x: any) => {
      const payoutFallback = Number(x?.payout_sales_sum || 0) - Number(x?.payout_returns_sum || 0);
      const payoutNet = Number(x?.payout_net ?? payoutFallback);
      const logistics = Number(x?.logistics_sum || 0);
      const storage = Number(x?.storage_sum || 0);
      const fine = Number(x?.fine_sum || 0);
      const withhold = Number(x?.withhold_sum || 0);
      const toPay = payoutNet - logistics - storage - fine - withhold;
      return { ...x, payout_net: payoutNet, to_pay_total: toPay };
    });
  };

  const fetchUploadedHistoryDetailsByIds = async (ids: string[]) => {
    const cleanIds = Array.from(new Set((ids || []).map((x) => String(x || '').trim()).filter(Boolean)));
    if (!cleanIds.length) return [] as any[];
    const { data, error } = await supabase
      .from('analytics_upload_history')
      .select('id, summary_json, analytics_json')
      .in('id', cleanIds as any)
      .limit(Math.max(1, cleanIds.length));
    if (error) throw error;
    return Array.isArray(data) ? data : [];
  };

  const openUploadedHistoryItem = async (item: any) => {
    try {
      let analytics = Array.isArray(item?.analytics_json) ? item.analytics_json : [];
      let summary = item?.summary_json || null;
      if ((!analytics.length || !summary) && item?.id) {
        const rows = await fetchUploadedHistoryDetailsByIds([String(item.id)]);
        const found = (rows || [])[0] || null;
        if (found) {
          analytics = Array.isArray(found?.analytics_json) ? found.analytics_json : analytics;
          summary = found?.summary_json || summary;
        }
      }
      if (!Array.isArray(analytics) || analytics.length === 0) {
        showToast('В этом отчёте нет сохранённых данных аналитики', 'error');
        return;
      }

      const recalcedAnalytics = recalcAnalyticsToPayWithoutAcquiring(analytics);

      const dateCandidates = recalcedAnalytics
        .map((x: any) => new Date(x?.operation_date || x?.date || x?.created_at || ''))
        .filter((d: Date) => !Number.isNaN(d.getTime()))
        .sort((a: Date, b: Date) => a.getTime() - b.getTime());

      const summaryTaxRate = getUploadedTaxRate(summary);
      const normalizedSummary = summary ? {
        ...summary,
        return_qty: recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.return_qty || 0), 0),
        acquiring_sum: recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.acquiring_sum || 0), 0),
        acquiring_percent: (recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.sales_net || 0), 0) > 0)
          ? (recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.acquiring_sum || 0), 0) / recalcedAnalytics.reduce((acc: number, x: any) => acc + Number(x?.sales_net || 0), 0)) * 100
          : 0,
        profit_total: recalcedAnalytics.reduce((acc: number, x: any) => {
          const sold = Number(x?.sold_qty || 0);
          const cost = Number(uploadedPersistedCostByCode[String(x?.code || '').trim()] || 0);
          const avg = sold > 0 ? (Number(x?.to_pay_total || 0) / sold) - cost : 0;
          const baseProfit = avg * sold;
          const taxValue = Number(x?.sales_net || 0) * summaryTaxRate;
          return acc + (baseProfit - taxValue);
        }, 0),
        period_start: summary?.period_start || (dateCandidates[0] ? dateCandidates[0].toISOString() : null),
        period_end: summary?.period_end || (dateCandidates.length ? dateCandidates[dateCandidates.length - 1].toISOString() : null),
      } : summary;

      setUploadedReportAnalytics(recalcedAnalytics);
      setUploadedReportSummary(normalizedSummary);
      setUploadedDailySeries({});
      setUploadedChartKey('');
      setUploadedViewTab('table');

      if (item?.id) {
        try {
          await supabase
            .from('analytics_upload_history')
            .update({ analytics_json: recalcedAnalytics, summary_json: normalizedSummary })
            .eq('id', item.id);
        } catch {}
      }

      showToast('Отчёт открыт из истории', 'success');
    } catch (e) {
      console.error('openUploadedHistoryItem error', e);
      showToast('Не удалось открыть отчёт из истории', 'error');
    }
  };


  const openUploadedHistoryMonth = async (items: any[]) => {
    const rows = Array.isArray(items) ? items : [];
    if (!rows.length) return;

    const grouped = new Map<string, any>();
    let periodStart: Date | null = null;
    let periodEnd: Date | null = null;

    const byId = new Map<string, any>();
    try {
      const ids = rows.map((r: any) => String(r?.id || '')).filter(Boolean);
      const details = await fetchUploadedHistoryDetailsByIds(ids);
      (details || []).forEach((d: any) => byId.set(String(d?.id || ''), d));
    } catch (e) {
      console.error('openUploadedHistoryMonth details fetch error', e);
    }

    rows.forEach((it: any) => {
      const detail = byId.get(String(it?.id || '')) || it;
      const arr = Array.isArray(detail?.analytics_json) ? detail.analytics_json : [];
      const summaryForDates = detail?.summary_json || it?.summary_json || {};
      const s0 = summaryForDates?.period_start ? new Date(summaryForDates.period_start) : null;
      const e0 = summaryForDates?.period_end ? new Date(summaryForDates.period_end) : null;
      if (s0 && !Number.isNaN(s0.getTime())) periodStart = !periodStart || s0 < periodStart ? s0 : periodStart;
      if (e0 && !Number.isNaN(e0.getTime())) periodEnd = !periodEnd || e0 > periodEnd ? e0 : periodEnd;

      const sourceYear = new Date(summaryForDates?.period_start || summaryForDates?.period_end || summaryForDates?.created_at || '').getFullYear();
      const sourceTaxRate = getTaxRateByYear(sourceYear);

      arr.forEach((r: any) => {
        const code = String(r?.code || '').trim();
        const name = String(r?.name || 'Без названия').trim();
        const key = `${code}|${name}`;
        const cur = grouped.get(key) || {
          code,
          name,
          sales_net: 0,
          returns_gross: 0,
          logistics_sum: 0,
          payout_sum: 0,
          payout_net: 0,
          fine_sum: 0,
          storage_sum: 0,
          withhold_sum: 0,
          to_pay_total: 0,
          sold_net_qty: 0,
          sold_qty: 0,
          return_qty: 0,
          acquiring_sum: 0,
          tax_sum: 0,
          acquiring_percent_sum: 0,
          acquiring_percent_count: 0,
          size_stats: {},
        };

        cur.sales_net += Number(r?.sales_net || 0);
        cur.returns_gross += Number(r?.returns_gross || 0);
        cur.logistics_sum += Number(r?.logistics_sum || 0);
        cur.payout_sum += Number(r?.payout_sum || 0);
        cur.payout_net += Number(r?.payout_net || 0);
        cur.fine_sum += Number(r?.fine_sum || 0);
        cur.storage_sum += Number(r?.storage_sum || 0);
        cur.withhold_sum += Number(r?.withhold_sum || 0);
        cur.to_pay_total += (Number(r?.payout_net || 0) - Number(r?.logistics_sum || 0) - Number(r?.storage_sum || 0) - Number(r?.fine_sum || 0) - Number(r?.withhold_sum || 0));
        cur.sold_net_qty += Number(r?.sold_net_qty || 0);
        cur.sold_qty += Number(r?.sold_qty || r?.sold_net_qty || 0);
        cur.return_qty += Number(r?.return_qty || 0);
        cur.acquiring_sum += Number(r?.acquiring_sum || 0);
        cur.tax_sum += Number(r?.tax_sum ?? (Number(r?.sales_net || 0) * sourceTaxRate));

        const ap = Number(r?.acquiring_percent || 0);
        if (ap > 0) {
          cur.acquiring_percent_sum += ap;
          cur.acquiring_percent_count += 1;
        }

        const sizeArr = Array.isArray(r?.size_breakdown_list) ? r.size_breakdown_list : [];
        sizeArr.forEach((sz: any) => {
          const sizeKey = String(sz?.size || 'Без размера');
          const prev = cur.size_stats[sizeKey] || {
            size: sizeKey,
            sales_net: 0,
            returns_gross: 0,
            logistics_sum: 0,
            payout_net: 0,
            fine_sum: 0,
            storage_sum: 0,
            withhold_sum: 0,
            to_pay_total: 0,
            sold_net_qty: 0,
            sold_qty: 0,
            return_qty: 0,
            acquiring_sum: 0,
            tax_sum: 0,
            acquiring_percent_sum: 0,
            acquiring_percent_count: 0,
          };
          prev.sales_net += Number(sz?.sales_net || 0);
          prev.returns_gross += Number(sz?.returns_gross || 0);
          prev.logistics_sum += Number(sz?.logistics_sum || 0);
          prev.payout_net += Number(sz?.payout_net || 0);
          prev.fine_sum += Number(sz?.fine_sum || 0);
          prev.storage_sum += Number(sz?.storage_sum || 0);
          prev.withhold_sum += Number(sz?.withhold_sum || 0);
          prev.to_pay_total += (Number(sz?.payout_net || 0) - Number(sz?.logistics_sum || 0) - Number(sz?.storage_sum || 0) - Number(sz?.fine_sum || 0) - Number(sz?.withhold_sum || 0));
          prev.sold_net_qty += Number(sz?.sold_net_qty || 0);
          prev.sold_qty += Number(sz?.sold_qty || sz?.sold_net_qty || 0);
          prev.return_qty += Number(sz?.return_qty || 0);
          prev.acquiring_sum += Number(sz?.acquiring_sum || 0);
          prev.tax_sum += Number(sz?.tax_sum || 0);
          const apSz = Number(sz?.acquiring_percent || 0);
          if (apSz > 0) {
            prev.acquiring_percent_sum += apSz;
            prev.acquiring_percent_count += 1;
          }
          cur.size_stats[sizeKey] = prev;
        });

        grouped.set(key, cur);
      });
    });

    const compareSizesAscLocal = (aSize: string, bSize: string) => {
      const prep = (v: string) => String(v || '').trim().toUpperCase();
      const a = prep(aSize);
      const b = prep(bSize);
      const rank = (v: string) => {
        if (!v || v === 'БЕЗ РАЗМЕРА' || v === 'БЕЗ Р-РА' || v === 'NONE' || v === 'NO SIZE') return 100000;

        const fixed: Record<string, number> = {
          XXS: 10,
          XS: 20,
          S: 30,
          M: 40,
          L: 50,
          XL: 60,
          XXL: 70,
          XXXL: 80,
          XXXXL: 90,
        };
        if (fixed[v] != null) return fixed[v];

        const xL = v.match(/^X+L$/i);
        if (xL) return 50 + String(v).replace(/[^X]/gi, '').length * 10;

        const numXL = v.match(/^(\d+)\s*XL$/i);
        if (numXL) return 60 + Number(numXL[1]) * 10;

        const pureNum = Number(v);
        if (!Number.isNaN(pureNum) && v !== '') return 500 + pureNum;

        return 90000;
      };
      const ra = rank(a);
      const rb = rank(b);
      if (ra !== rb) return ra - rb;
      return a.localeCompare(b, 'ru', { numeric: true });
    };

    const analytics = Array.from(grouped.values()).map((x: any) => {
      const sizeBreakdown = Object.values(x?.size_stats || {})
        .map((sz: any) => ({
          ...sz,
          acquiring_percent: Number(sz?.sales_net || 0) > 0 ? (Number(sz?.acquiring_sum || 0) / Number(sz?.sales_net || 0)) * 100 : 0,
        }))
        .sort((a: any, b: any) => compareSizesAscLocal(String(a?.size || ''), String(b?.size || '')));
      return {
        ...x,
        acquiring_percent: Number(x.sales_net || 0) > 0 ? (Number(x.acquiring_sum || 0) / Number(x.sales_net || 0)) * 100 : 0,
        size_breakdown: sizeBreakdown.map((z: any) => `${z.size}: ${Number(z.sold_net_qty || 0) - Number(z.return_qty || 0)}`).join(' • '),
        size_breakdown_list: sizeBreakdown,
      };
    }).sort((a: any, b: any) => Number(b.sales_net || 0) - Number(a.sales_net || 0));

    const summary = {
      report_number: null,
      period_start: periodStart ? periodStart.toISOString() : null,
      period_end: periodEnd ? periodEnd.toISOString() : null,
      items: analytics.length,
      sales_net: analytics.reduce((acc: number, x: any) => acc + Number(x.sales_net || 0), 0),
      returns_gross: analytics.reduce((acc: number, x: any) => acc + Number(x.returns_gross || 0), 0),
      logistics_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.logistics_sum || 0), 0),
      payout_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.payout_sum || 0), 0),
      payout_net: analytics.reduce((acc: number, x: any) => acc + Number(x.payout_net || 0), 0),
      fine_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.fine_sum || 0), 0),
      storage_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.storage_sum || 0), 0),
      withhold_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.withhold_sum || 0), 0),
      to_pay_total: analytics.reduce((acc: number, x: any) => acc + Number(x.to_pay_total || 0), 0),
      sold_qty: analytics.reduce((acc: number, x: any) => acc + Number(x.sold_qty || 0), 0),
      return_qty: analytics.reduce((acc: number, x: any) => acc + Number(x.return_qty || 0), 0),
      acquiring_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.acquiring_sum || 0), 0),
      acquiring_percent: (analytics.reduce((acc: number, x: any) => acc + Number(x.sales_net || 0), 0) > 0)
        ? (analytics.reduce((acc: number, x: any) => acc + Number(x.acquiring_sum || 0), 0) / analytics.reduce((acc: number, x: any) => acc + Number(x.sales_net || 0), 0)) * 100
        : 0,
      tax_sum: analytics.reduce((acc: number, x: any) => acc + Number(x.tax_sum || 0), 0),
      profit_total: analytics.reduce((acc: number, x: any) => {
        const sold = Number(x.sold_qty || 0);
        const cost = Number(uploadedPersistedCostByCode[String(x.code || '').trim()] || 0);
        const avg = sold > 0 ? (Number(x.to_pay_total || 0) / sold) - cost : 0;
        const baseProfit = avg * sold;
        const taxValue = Number(x.tax_sum || 0);
        return acc + (baseProfit - taxValue);
      }, 0),
    };

    setUploadedReportAnalytics(analytics);
    setUploadedReportSummary(summary);
    setUploadedDailySeries({});
    setUploadedChartKey('');
    setUploadedViewTab('table');
    showToast('Открыт объединённый отчёт за месяц', 'success');
  };


  const openUploadedHistorySelected = () => {
    const selected = (uploadedHistory || []).filter((h: any) => uploadedHistorySelectedIds[String(h.id)]);
    if (!selected.length) {
      showToast('Выберите хотя бы один отчёт', 'error');
      return;
    }
    openUploadedHistoryMonth(selected as any[]);
    setUploadedHistoryPickerOpen(false);
  };

  const deleteUploadedHistoryItem = async (id: string, fileName?: string) => {
    if (!id) return;
    const label = String(fileName || 'этот отчёт');
    const ok = window.confirm(`Удалить из истории: ${label}?`);
    if (!ok) return;
    try {
      const { error } = await supabase.from('analytics_upload_history').delete().eq('id', id);
      if (error) throw error;
      setUploadedHistory((prev) => (prev || []).filter((x: any) => String(x.id) !== String(id)));
      showToast('Отчёт удалён из истории', 'success');
    } catch (e) {
      console.error('deleteUploadedHistoryItem error', e);
      showToast('Не удалось удалить отчёт из истории', 'error');
    }
  };

  const saveUploadedReportHistory = async (fileName?: string, summaryArg?: any, analyticsArg?: any[]) => {
    const summaryToSave = summaryArg || uploadedReportSummary;
    const analyticsToSave = analyticsArg || uploadedReportAnalytics;
    if (!uploadedSelectedSupplierId || !summaryToSave || !analyticsToSave?.length) return;
    const supplier = (suppliers || []).find((s: any) => String(s?.id) === String(uploadedSelectedSupplierId));
    try {
      const reportNumber = String((summaryToSave as any)?.report_number || '').trim();
      let duplicateId: string | null = null;
      if (reportNumber) {
        const { data: existingRows, error: checkError } = await supabase
          .from('analytics_upload_history')
          .select('id, summary_json, created_at')
          .eq('supplier_id', uploadedSelectedSupplierId)
          .order('created_at', { ascending: false })
          .limit(400);
        if (checkError) throw checkError;

        const psIso = (summaryToSave as any)?.period_start ? new Date((summaryToSave as any).period_start).toISOString().slice(0, 10) : '';
        const peIso = (summaryToSave as any)?.period_end ? new Date((summaryToSave as any).period_end).toISOString().slice(0, 10) : '';

        const duplicate = (existingRows || []).find((x: any) => {
          const rn = String(x?.summary_json?.report_number || '').trim();
          const xps = x?.summary_json?.period_start ? new Date(x.summary_json.period_start).toISOString().slice(0, 10) : '';
          const xpe = x?.summary_json?.period_end ? new Date(x.summary_json.period_end).toISOString().slice(0, 10) : '';
          return rn === reportNumber && xps === psIso && xpe === peIso;
        });

        if (duplicate?.id) duplicateId = String(duplicate.id);
      }

      const ps = (summaryToSave as any)?.period_start ? new Date((summaryToSave as any).period_start).toLocaleDateString('ru-RU') : '-';
      const pe = (summaryToSave as any)?.period_end ? new Date((summaryToSave as any).period_end).toLocaleDateString('ru-RU') : '-';
      const supplierName = supplier?.name || 'Без поставщика';
      const defaultHistoryName = `Период отчета: ${ps} - ${pe}, ${supplierName}`;

      const compactAnalyticsRow = (row: any) => {
        const sizeRows = Array.isArray(row?.size_breakdown_list) ? row.size_breakdown_list.slice(0, 20) : [];
        return {
          code: row?.code || '',
          name: row?.name || '',
          sales_net: Number(row?.sales_net || 0),
          returns_gross: Number(row?.returns_gross || 0),
          logistics_sum: Number(row?.logistics_sum || 0),
          payout_sum: Number(row?.payout_sum || 0),
          payout_net: Number(row?.payout_net || 0),
          fine_sum: Number(row?.fine_sum || 0),
          storage_sum: Number(row?.storage_sum || 0),
          withhold_sum: Number(row?.withhold_sum || 0),
          to_pay_total: Number(row?.to_pay_total || 0),
          sold_qty: Number(row?.sold_qty || 0),
          return_qty: Number(row?.return_qty || 0),
          acquiring_sum: Number(row?.acquiring_sum || 0),
          acquiring_percent: Number(row?.acquiring_percent || 0),
          tax_sum: Number(row?.tax_sum || 0),
          size_breakdown: row?.size_breakdown || '',
          size_breakdown_list: sizeRows.map((sz: any) => ({
            size: sz?.size || '',
            sold_qty: Number(sz?.sold_qty || 0),
            return_qty: Number(sz?.return_qty || 0),
            sales_net: Number(sz?.sales_net || 0),
            returns_gross: Number(sz?.returns_gross || 0),
            logistics_sum: Number(sz?.logistics_sum || 0),
            payout_net: Number(sz?.payout_net || 0),
            fine_sum: Number(sz?.fine_sum || 0),
            storage_sum: Number(sz?.storage_sum || 0),
            withhold_sum: Number(sz?.withhold_sum || 0),
            to_pay_total: Number(sz?.to_pay_total || 0),
            acquiring_sum: Number(sz?.acquiring_sum || 0),
          })),
        };
      };
      const analyticsSafe = Array.isArray(analyticsToSave) ? analyticsToSave.slice(0, ANALYTICS_JSON_DB_LIMIT).map(compactAnalyticsRow) : [];
      const analyticsTruncated = Array.isArray(analyticsToSave) && analyticsToSave.length > analyticsSafe.length;
      const summarySafe = { ...(summaryToSave || {}), analytics_truncated: analyticsTruncated, analytics_rows_saved: analyticsSafe.length, analytics_rows_original: Array.isArray(analyticsToSave) ? analyticsToSave.length : 0 } as any;

      const payload = {
        supplier_id: uploadedSelectedSupplierId,
        supplier_name: supplierName,
        file_name: defaultHistoryName,
        summary_json: summarySafe,
        analytics_json: analyticsSafe,
      };

      const payloadBytes = new TextEncoder().encode(JSON.stringify(payload)).length;
      if (payloadBytes > 7_000_000) {
        payload.analytics_json = [];
        payload.summary_json = { ...summarySafe, analytics_json_skipped: true, analytics_rows_saved: 0 };
        showToast('Агрегаты слишком большие для БД: сохранена только сводка и исходный файл', 'warning');
      }

      if (duplicateId) {
        const { error } = await supabase
          .from('analytics_upload_history')
          .update(payload)
          .eq('id', duplicateId);
        if (error) throw error;
        showToast(`Отчёт №${reportNumber} обновлён`, 'success');
      } else {
        const { error } = await supabase.from('analytics_upload_history').insert(payload);
        if (error) throw error;
      }

      if (analyticsTruncated) {
        showToast(`Сохранена облегчённая версия: ${analyticsSafe.length.toLocaleString('ru-RU')} из ${analyticsToSave.length.toLocaleString('ru-RU')} строк аналитики`, 'warning');
      }

      loadUploadedReportHistory(uploadedSelectedSupplierId);
    } catch (e: any) {
      console.error('saveUploadedReportHistory error', e);
      showToast(`Не удалось сохранить отчёт в "Отчёты": ${e?.message || 'ошибка'}`, 'error');
    }
  };

  const normalizeNmId = (v: any) => String(v ?? '').replace(/\D+/g, '').replace(/^0+/, '');
  const getUploadedPhotoCandidates = (code: string) => {
    const raw = String(code || '').trim();
    const norm = normalizeNmId(raw);
    const candidates: string[] = [];

    if (uploadedPhotoMap[raw]) candidates.push(uploadedPhotoMap[raw]);
    if (norm && uploadedPhotoMap[norm]) candidates.push(uploadedPhotoMap[norm]);

    const failed = uploadedFailedPhotoUrlsRef.current;
    return Array.from(new Set(candidates.filter(Boolean))).filter((u) => !failed.has(String(u)));
  };
  const getUploadedPhoto = (code: string) => getUploadedPhotoCandidates(code)[0] || '';

  const enrichUploadedPhotosByApi = async (sourceAnalytics?: any[]) => {
    const analyticsSource = Array.isArray(sourceAnalytics) ? sourceAnalytics : uploadedReportAnalytics;
    if (!analyticsSource.length) {
      showToast('Сначала загрузите отчет', 'error');
      return;
    }
    if (analyticsSource.length > 2000) {
      showToast('Для большого отчёта автообновление фото отключено (чтобы не перегружать систему)', 'info');
      return;
    }

    try {
      const normalized = (v: any) => String(v ?? '').replace(/\D+/g, '').replace(/^0+/, '');
      const allCovered = (analyticsSource || []).every((r: any) => {
        const raw = String(r?.code || '').trim();
        const norm = normalized(raw);
        return !!((uploadedPhotoMap || {})[raw] || (norm && (uploadedPhotoMap || {})[norm]));
      });
      if (allCovered) {
        showToast('Фото уже загружены, автообновление пропущено', 'info');
        return;
      }

      setUploadedPhotoLoading(true);
      uploadedFailedPhotoUrlsRef.current.clear();
      const nextMap: Record<string, string> = { ...(uploadedPhotoMap || {}) };

      // 1) try supplier cache first
      if (uploadedSelectedSupplierId) {
        const { data: cacheRows, error: cacheErr } = await supabase
          .from('wb_products_cache')
          .select('product_json')
          .eq('supplier_id', uploadedSelectedSupplierId)
          .limit(10000);
        if (!cacheErr) {
          (cacheRows || []).forEach((row: any) => {
            const p = row?.product_json || {};
            const nm = normalizeNmId(p?.nmID || p?.nm_id || 0);
            const vendorCode = String(p?.vendorCode || p?.supplierArticle || p?.article || '').trim();
            const first = (Array.isArray(p?.photos) && p.photos[0]) || (Array.isArray(p?.mediaFiles) && p.mediaFiles[0]) || '';
            let src = typeof first === 'string' ? first : (first?.big || first?.c246x328 || first?.tm || '');
            src = String(src || '').trim();
            if (src && src.startsWith('//')) src = `https:${src}`;
            if (/^https?:\/\//i.test(src)) {
              if (nm) nextMap[String(nm)] = src;
              if (vendorCode) nextMap[vendorCode] = src;
            }
          });
        }
      }

      // 2) public WB card API for missing
      const missing = analyticsSource
        .map((r: any) => {
          const raw = String(r.code || '').trim();
          const norm = normalizeNmId(raw);
          return norm || raw;
        })
        .filter((c: string) => c && c !== '0' && !nextMap[c])
        .slice(0, 200);

      // Strict DB-only photo mode: do not synthesize external WB image URLs.
      if (missing.length) {
        console.info('DB-only photo mode, no external fallback for codes:', missing.slice(0, 10));
      }

      setUploadedPhotoMap(nextMap);
      showToast('Фото обновлены из базы', 'success');
    } catch (e: any) {
      showToast(e?.message || 'Ошибка загрузки фото', 'error');
    } finally {
      setUploadedPhotoLoading(false);
    }
  };

