  useEffect(() => {
    if (!wbDragState) return;

    const onMove = (e: MouseEvent) => {
      const dx = e.clientX - wbDragState.startX;
      const dy = e.clientY - wbDragState.startY;

      setWbLayoutEditor((prev: any) => {
        const group = prev[wbDragState.layout];
        if (!group) return prev;
        return {
          ...prev,
          [wbDragState.layout]: {
            ...group,
            [wbDragState.xKey]: Math.max(0, wbDragState.baseX + dx),
            [wbDragState.yKey]: Math.max(0, wbDragState.baseY + dy),
          }
        };
      });
    };

    const onUp = () => setWbDragState(null);
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
    };
  }, [wbDragState]);

